// ============================================================
// Date examen licență ULBS — Iulie 2026 – Februarie 2027
// 4 discipline x 50 întrebări, format grilă A/B/C/D
// Răspunsuri corecte verificate prin extracție programatică din PDF-urile sursă
// ============================================================

const QUIZ_DATA = {
management: {
  label: "Management",
  color: "#2E5339",
  questions: [
{q:"Următoarea afirmație privind munca unui manager este falsă:",o:["poate presupune coordonarea unui departament sau supravegherea unei singure persoane","poate avea în vedere coordonarea activităților unei echipe alcătuite din membri aparținând unor departamente diferite","nu poate presupune și responsabilități care nu au legătură cu coordonarea sau controlul muncii altora","poate avea în vedere coordonarea activităților unor persoane din afara organizației (practicanți)"],a:2,m:"Corect: C. Conform suportului de curs (Introducere în management), munca unui manager poate include și responsabilități fără legătură cu coordonarea sau controlul muncii altora (ex. sarcini proprii de execuție) — deci afirmația C este falsă. A, B și D descriu corect variantele muncii manageriale."},
{q:"Gruparea deliberată a unor persoane, constituită pentru a îndeplini anumite scopuri specifice – definește:",o:["grupa informală","organizația","departamentul","structura organizatorică"],a:1,m:"Corect: B. Organizația este definită în curs ca o grupare deliberată de persoane, constituită pentru a îndeplini anumite scopuri specifice. Departamentul și structura organizatorică sunt componente/instrumente ale organizației, nu definiția ei."},
{q:"Eficiența presupune:",o:["nivel redus al risipei de resurse","a face lucrurile care trebuie","a face acele activități care vor conduce la atingerea scopurilor","nivel ridicat de atingere a scopurilor"],a:0,m:"Corect: A. Eficiența = măsura productivității utilizării resurselor, adică nivel redus al risipei de resurse („a face lucrurile cum trebuie”). B, C și D descriu eficacitatea („a face lucrurile care trebuie” / gradul de atingere a scopurilor)."},
{q:"Determinarea scopurilor, stabilirea strategiilor pentru atingerea acestora, și dezvoltarea planurilor pentru integrarea și coordonarea activităților organizației – se realizează prin intermediul:",o:["procedurilor organizaționale standardizate","funcției de organizare a managerului","programelor și bugetelor organizaționale","funcției de planificare a managementului"],a:3,m:"Corect: D. Determinarea scopurilor, stabilirea strategiilor și dezvoltarea planurilor pentru integrarea și coordonarea activităților reprezintă exact definiția funcției de planificare a managementului, prima etapă a procesului managerial."},
{q:"Potrivit lui Mintzberg, în categoria rolurilor manageriale decizionale se regăsesc cele de:",o:["alocator de resurse, negociator, mânuitor de disfuncționalități","figură reprezentativă, lider, negociator","lider, diseminator, purtător de cuvânt","antreprenor, observator, diseminator"],a:0,m:"Corect: A. La Mintzberg, rolurile decizionale sunt: antreprenor, mânuitor de disfuncționalități, alocator de resurse și negociator. Variantele B–D amestecă roluri interpersonale (figură reprezentativă, lider) și informaționale (observator, diseminator, purtător de cuvânt)."},
{q:"Abilitățile conceptuale sunt cele mai importante pentru:",o:["executanți","managerii de nivel superior","managerii de nivel inferior","managerii de nivel mediu"],a:1,m:"Corect: B. Conform modelului lui Katz, abilitățile conceptuale (viziune de ansamblu, gândire abstractă) sunt cele mai importante pentru managerii de nivel superior; abilitățile tehnice primează la nivelurile inferioare, iar cele umane sunt importante la toate nivelurile."},
{q:"Conform matricei incertitudinii mediului, mediul complex și stabil presupune:",o:["dinamism și impredictibilitate; multe componente; componentele nu sunt similare între ele și se schimbă în permanență; nevoie ridicată de cunoaștere amănunțită a componentelor","stabilitate și predictibilitate; puține componente; componentele nu sunt similare între ele dar rămân în principiu aceleași; nevoie ridicată de cunoaștere amănunțită a componentelor","stabilitate și predictibilitate; multe componente; componentele nu sunt similare între ele dar rămân în principiu aceleași; nevoie ridicată de cunoaștere amănunțită a componentelor","dinamism și impredictibilitate; puține componente; componentele relativ similare, care rămân în principiu aceleași; nevoie minimă pentru cunoașterea amănunțită a componentelor"],a:2,m:"Corect: C. În matricea incertitudinii mediului, mediul complex și stabil = stabilitate și predictibilitate (dimensiunea „stabil”), plus multe componente nesimilare care rămân în principiu aceleași și nevoie ridicată de cunoaștere amănunțită (dimensiunea „complex”). A descrie mediul complex-dinamic, D pe cel simplu-dinamic."},
{q:"Orice constituent al mediului firmei (organizație/grup/persoană) care este afectat de deciziile si acțiunile acesteia – reprezintă un:",o:["angajat","acționar","manager","stakeholder"],a:3,m:"Corect: D. Stakeholderul este orice constituent al mediului firmei (organizație/grup/persoană) afectat de deciziile și acțiunile acesteia — definiție preluată ca atare în suportul de curs."},
{q:"Care dintre următoarele afirmații reflectă cel mai bine un principiu esențial al Managementului bazat pe dovezi (EBM)?",o:["managerul trebuie să ia în considerare, în mod sistematic, expertiza, dovezile externe, valorile părților interesate și contextul organizațional, acordând prioritate factorului cel mai relevant","deciziile ar trebui să se bazeze în principal pe intuiția managerului, deoarece aceasta prevalează față de dovezile externe","opiniile părților interesate sunt singura bază pentru luarea deciziilor în EBM","contextul organizațional are un impact minim asupra procesului decizional în EBM"],a:0,m:"Corect: A. Principiul esențial al managementului bazat pe dovezi (EBM): luarea în considerare sistematică a expertizei manageriale, a dovezilor externe, a valorilor părților interesate și a contextului organizațional, cu prioritizarea factorului celui mai relevant. B, C și D absolutizează câte un singur factor, contrar EBM."},
{q:"Procesul care ajută angajații să se adapteze la cultura organizațională – poartă denumirea de:",o:["formare","socializare","armonizare","învățare"],a:1,m:"Corect: B. Socializarea este procesul prin care angajații (mai ales cei noi) se adaptează la cultura organizațională — termenul consacrat în capitolul despre cultura organizațională."},
{q:"Abilitatea unei firme de a-și atinge scopurile de afaceri (de business) și a creste valoarea pe termen lung a acționarilor prin integrarea oportunităților economice, sociale și de mediu în strategiile sale de afaceri – definește:",o:["managementul verde","competența managerială","sustenabilitatea","stilul de management"],a:2,m:"Corect: C. Sustenabilitatea = abilitatea firmei de a-și atinge scopurile de business și de a crește valoarea pe termen lung a acționarilor prin integrarea oportunităților economice, sociale și de mediu în strategii — definiția din curs."},
{q:"O companie analizează lansarea unui nou produs într-o piață complet nouă, unde nu există date despre preferințele consumatorilor și legislația se schimbă frecvent. Managerul nu poate estima șansele de succes sau eșec. În ce condiție decizională se află acesta?",o:["certitudine – are toate informațiile necesare și poate prezice rezultatul","risc – are suficiente date pentru a estima probabilitatea succesului","incertitudine – nu are date suficiente și nu poate estima rezultatul","omnipotență – deține toate resursele și poate influența complet rezultatul"],a:2,m:"Corect: C. Lipsesc datele despre preferințe, legislația se schimbă frecvent, iar managerul nu poate estima probabilitățile de succes/eșec → condiție de incertitudine. Certitudinea presupune informații complete, riscul presupune probabilități estimabile, iar „omnipotența” nu e o condiție decizională reală."},
{q:"Angajamentul unei firme ca, dincolo de obligațiile sale legale și economice, să facă ceea ce trebuie (adică e corect din punct de vedere etic), acționând într-o manieră benefică pentru societate - definește:",o:["strategia corporatistă","funcția de organizare a managementului","filantropia corporatistă","responsabilitatea socială"],a:3,m:"Corect: D. Responsabilitatea socială = angajamentul firmei ca, dincolo de obligațiile legale și economice, să facă ceea ce este corect etic, acționând în beneficiul societății. Filantropia corporatistă este doar o formă punctuală, nu definiția."},
{q:"Raționalitatea în luarea deciziilor nu presupune că:",o:["managerii iau decizii completamente obiective și logice – în interesul firmei","procesul decizional este limitat/restrâns de abilitatea personală a managerului de procesare a informației","situația/problema cu care se confruntă managerul e clară și lipsită de ambiguități","decidentul cunoaște atât toate alternativele decizionale posibile, cât și consecințele acestora"],a:1,m:"Corect: B. Raționalitatea (perfectă) presupune decident complet obiectiv și logic, problemă clară, cunoașterea tuturor alternativelor și consecințelor (A, C, D). Limitarea procesului decizional de capacitatea personală de procesare a informației definește raționalitatea limitată (bounded rationality) — deci B NU aparține raționalității."},
{q:"Procedura este:",o:["un enunț explicit care le spune managerilor ce pot face și ce nu","un ghid ce stabilește parametrii generali pentru luarea deciziilor","un set secvențial de pași folosiți pentru a răspunde unei probleme structurate","folosirea sistematică a celor mai bune date și informații disponibile pentru îmbunătățirea practicii manageriale"],a:2,m:"Corect: C. Procedura = set secvențial de pași folosiți pentru a răspunde unei probleme structurate. A definește regula, B definește politica, D definește managementul bazat pe dovezi."},
{q:"Următoarea afirmație e falsă:",o:["managerii de la nivelurile inferioare se bazează de regulă pe decizii programate","managerii de la nivelurile superioare soluționează situațiile neobișnuite sau dificile","managerii de la nivelurile superioare deleagă deciziile de rutină subordonaților lor","managerii de la nivelurile inferioare se confruntă de regulă cu probleme nestructurate"],a:3,m:"Corect: D. Afirmația falsă: managerii de la nivelurile inferioare se confruntă de regulă cu probleme structurate, repetitive (rezolvate prin decizii programate), nu nestructurate — acestea urcă spre nivelurile superioare (B, C adevărate)."},
{q:"Tendința decidenților de a-și asuma rapid succesul și de a pune eșecurile proprii pe seama factorilor externi – reprezintă eroarea/inclinația de/spre:",o:["infatuare","autofavorizare","percepție selectivă","confirmare"],a:1,m:"Corect: B. Eroarea de autofavorizare (self-serving bias) = tendința decidenților de a-și asuma rapid succesele și de a atribui eșecurile factorilor externi. Infatuarea = încredere exagerată în sine; percepția selectivă și confirmarea privesc filtrarea informațiilor."},
{q:"Planificarea (ca funcție a managementului) reduce incertitudinea pentru că:",o:["definește țintele sau standardele necesare pentru control","oferă direcție managerilor și executanților","forțează managerii la o abordare proactivă","evidențiază ineficiențele, ce pot fi apoi corectate/eliminate"],a:2,m:"Corect: C. Planificarea reduce incertitudinea pentru că forțează managerii să privească înainte, să anticipeze schimbarea și să adopte o abordare proactivă. A, B și D sunt alte beneficii ale planificării (standarde pentru control, direcție, evidențierea risipei), nu mecanismul reducerii incertitudinii."},
{q:"Documentele care conturează modul în care vor fi atinse scopurile – sunt:",o:["planurile","bugetele","normele formale","programele"],a:0,m:"Corect: A. Planurile sunt documentele care conturează modul în care vor fi atinse scopurile (alocarea resurselor, calendar, acțiuni). Bugetele și programele sunt tipuri particulare de planuri."},
{q:"Planurile strategice sunt:",o:["pe termen lung, direcționale, unice","pe termen lung, specifice, unice","pe termen lung, direcționale, permanente","pe termen scurt, specifice, permanente"],a:0,m:"Corect: A. Conform clasificării din curs, planurile strategice sunt pe termen lung, direcționale (flexibile, orientative) și unice (de unică folosință, elaborate pentru situații specifice)."},
{q:"Elementele fundamentale ale programelor de tipul MBO (managementul prin obiective) sunt: a) feedback privind motivarea; b) feedback privind performanța; c) interval temporal explicit; d) interval temporal implicit; e) proces decizional autocratic; f) proces decizional participativ; g) specificitatea sarcinilor; h) specificitatea scopurilor/obiectivelor.",o:["(a, d, e, g)","(b, c, f, h)","(a, c, d, g)","(b, d, f, g)"],a:1,m:"Corect: B. Elementele fundamentale ale MBO: specificitatea scopurilor/obiectivelor, proces decizional participativ, interval temporal explicit și feedback privind performanța → (b, c, f, h)."},
{q:"Inteligența competitivă este considerată una dintre formele de scanare a mediului cu cea mai rapidă creștere deoarece:",o:["este cea mai ieftină metodă de culegere a datelor","se bazează exclusiv pe surse publice de informații","permite managerilor să anticipeze acțiunile concurenților, nu doar să reacționeze","elimină complet incertitudinea strategică"],a:2,m:"Corect: C. Inteligența competitivă crește rapid ca formă de scanare a mediului pentru că permite managerilor să anticipeze acțiunile concurenților, nu doar să reacționeze la ele. Nu e cea mai ieftină, nu se bazează exclusiv pe surse publice și nu elimină complet incertitudinea."},
{q:"Liderii tranzacționali se ghidează după principiul:",o:["inspirării și transformării followers","viziunii pe termen lung și schimbării culturii organizaționale","stimulării motivației intrinseci a angajaților","recompenselor oferite în schimbul productivității"],a:3,m:"Corect: D. Liderii tranzacționali conduc prin schimburi (tranzacții): recompense oferite în schimbul productivității. Inspirarea, viziunea și stimularea motivației intrinseci (A–C) definesc liderii transformaționali."},
{q:"Designul organizațional / proiectarea organizațională – are în vedere:",o:["reprezentarea vizuală a structurii unei organizații","gruparea formală a posturilor într-o organizație","crearea sau schimbarea structurii organizatorice","gruparea și structurarea muncii necesare îndeplinirii scopurilor organizaționale"],a:2,m:"Corect: C. Designul organizațional = procesul de creare sau schimbare a structurii organizatorice (deciziile privind specializarea, departamentalizarea, ierarhia, centralizarea, formalizarea). A descrie organigrama, B structura, D organizarea ca funcție."},
{q:"Organizația organică nu se caracterizează prin: a) circulație liberă a informațiilor; b) descentralizare; c) specializare accentuată; d) formalizare redusă; e) departamentalizare rigidă; f) pondere ierarhică redusă.",o:["(a, b, d)","(b, e, f)","(c, e, f)","(a, c, e)"],a:2,m:"Corect: C. Organizația organică se caracterizează prin circulație liberă a informațiilor, descentralizare, formalizare redusă, echipe flexibile. NU se caracterizează prin specializare accentuată, departamentalizare rigidă și pondere ierarhică redusă (acestea aparțin modelului mecanicist) → (c, e, f)."},
{q:"Factorii care influențează alegerea structurii organizatorice sunt: a) cultura organizațională; b) incertitudinea mediului; c) mărimea firmei; d) numărul nivelurilor manageriale; e) ponderea ierarhică; f) sistemele de control și recompensă; g) strategia firmei; h) tehnologia disponibilă.",o:["(a, b, c, d)","(e, f, g, h)","(a, c, e, g)","(b, c, g, h)"],a:3,m:"Corect: D. Factorii de contingență care influențează alegerea structurii: incertitudinea mediului, mărimea firmei, strategia firmei și tehnologia disponibilă → (b, c, g, h). Celelalte elemente (niveluri, pondere ierarhică) sunt componente ale structurii, nu factori de alegere."},
{q:"Structurile organizatorice tradiționale sunt: a) organizația fără granițe; b) structura organizatorică divizională; c) structura organizatorică funcțională; d) structura organizatorică matriceală; e) structura organizatorică pe bază de proiecte; f) structura organizatorică simplă; g) structura organizatorică tip rețea.",o:["(a, d, e)","(b, c, f)","(c, e, f)","(d, e, g)"],a:1,m:"Corect: B. Structurile organizatorice tradiționale: simplă, funcțională și divizională → (b, c, f). Organizația fără granițe, matriceală, pe proiecte și tip rețea sunt structuri contemporane/adaptive."},
{q:"În cadrul procesului de management al resurselor umane, localizarea, identificarea și atragerea candidaților capabili/potriviți – se realizează prin intermediul:",o:["recrutării","selecției","planificării RU","orientării"],a:0,m:"Corect: A. Recrutarea = localizarea, identificarea și atragerea candidaților capabili. Selecția înseamnă alegerea dintre candidați, planificarea RU determină necesarul, orientarea integrează noii angajați."},
{q:"Testele de simulare a performanței, formularele de aplicație și interviurile – reprezintă instrumente folosite pentru:",o:["recrutarea resurselor umane","selecția resurselor umane","evaluarea performanțelor resurselor umane","instruirea resurselor umane"],a:1,m:"Corect: B. Formularele de aplicație, testele de simulare a performanței și interviurile sunt instrumente de selecție a resurselor umane — servesc la a prezice care candidat va avea performanțe bune pe post."},
{q:"Incidentul critic, comparația interpersonală și managementul prin obiective – reprezintă tehnici folosite în:",o:["selecția resurselor umane","planificarea obiectivelor organizaționale","definirea strategiei firmei","evaluarea performanțelor resurselor umane"],a:3,m:"Corect: D. Incidentul critic, comparația interpersonală și managementul prin obiective sunt tehnici de evaluare a performanțelor resurselor umane, conform capitolului de MRU din curs."},
{q:"Procesul de management al resurselor umane reunește următoarele faze: a) identificarea si selecția angajaților competenți; b) instruirea resurselor umane; c) managementul performanței; d) actualizarea cunoștințelor si abilităților angajaților; e) recrutarea resurselor umane; f) retenția angajaților competenți și performanți; g) selecția resurselor umane.",o:["(a, d, f)","(b, e, g)","(c, f, g)","(d, e, f)"],a:0,m:"Corect: A. Procesul de MRU cuprinde trei faze: (1) identificarea și selecția angajaților competenți, (2) actualizarea cunoștințelor și abilităților angajaților, (3) retenția angajaților competenți și performanți → (a, d, f). Recrutarea, selecția și instruirea sunt activități în interiorul acestor faze."},
{q:"Următoarea afirmație e adevărată:",o:["buna comunicare reprezintă situația în care receptorul e de acord cu conținutul mesajului recepționat de la emițător","comunicarea interpersonală reprezintă ansamblul tiparelor, rețelelor, și sistemelor de comunicare din cadrul unei organizații","comunicarea perfectă are loc atunci când un gând / o idee transmis(ă) a fost recepționat(ă) și înțeles(înțeleasă) de către receptor exact așa cum a intenționat emițătorul","barierele comunicaționale pot fi cognitive sau emoționale, dar nu socio-culturale sau naționale"],a:2,m:"Corect: C. Comunicarea perfectă are loc atunci când gândul/ideea transmisă este recepționată și înțeleasă de receptor exact așa cum a intenționat emițătorul. A e falsă (buna comunicare ≠ acord), B descrie comunicarea organizațională, D e falsă (barierele pot fi și socio-culturale/naționale)."},
{q:"Metoda de comunicare aleasă de un manager va trebui să reflecte: a) nevoile expeditorului; b) nevoile receptorului; c) particularitățile canalului de comunicare; d) specificul mesajului; e) strategia organizației; f) structura organizației.",o:["(a, b, c, d)","(b, c, d, e)","(c, d, e, f)","(a, b, e, f)"],a:0,m:"Corect: A. Metoda de comunicare aleasă trebuie să reflecte nevoile expeditorului, nevoile receptorului, particularitățile canalului și specificul mesajului → (a, b, c, d). Strategia și structura organizației nu sunt criterii de alegere a metodei de comunicare."},
{q:"După direcția fluxului comunicațional, comunicarea poate fi: a) ascendentă; b) descendentă; c) formală; d) informală; e) laterală; f) oblică.",o:["(a, b, c, d)","(b, c, d, e)","(c, d, e, f)","(a, b, e, f)"],a:3,m:"Corect: D. După direcția fluxului comunicațional, comunicarea poate fi ascendentă, descendentă, laterală și oblică → (a, b, e, f). Formală/informală este o clasificare după alt criteriu (caracterul rețelei)."},
{q:"Elementele cheie ale motivării sunt: a) direcția; b) energia; c) persistența; d) recompensa; e) personalitatea.",o:["(a, d, e)","(b, c, d)","(a, b, c)","(b, d, e)"],a:2,m:"Corect: C. Elementele cheie ale motivării: energia (intensitatea efortului), direcția (orientarea spre scopuri) și persistența (menținerea efortului) → (a, b, c). Recompensa și personalitatea sunt factori de influență, nu elemente definitorii."},
{q:"Procesul prin care eforturile unei persoane sunt dinamizate, direcționate și susținute în vederea atingerii unui scop – definește:",o:["comportamentul organizațional","leadershipul","managementul","motivarea"],a:3,m:"Corect: D. Motivarea = procesul prin care eforturile unei persoane sunt dinamizate (energizate), direcționate și susținute în vederea atingerii unui scop — definiția exactă din curs."},
{q:"Aspectele esențiale ale preocupărilor în domeniul comportamentului organizațional nu vizează: a) cifra de afaceri; b) comportamentul contraproductiv; c) cota de piață; d) fluctuația forței de muncă; e) productivitatea angajaților; f) randamentul investițiilor; g) satisfacția în muncă.",o:["(b, d, e)","(d, e, g)","(a, c, f)","(c, e, g)"],a:2,m:"Corect: C. Comportamentul organizațional vizează productivitatea angajaților, satisfacția în muncă, fluctuația, comportamentul contraproductiv. NU vizează indicatorii financiari/de piață: cifra de afaceri, cota de piață, randamentul investițiilor → (a, c, f)."},
{q:"Măsura în care un lider e abordabil și arată preocupare personală pentru subordonați – definește:",o:["considerația","contextul motivațional","funcțiunea de misiune a leadership-ului","structurarea"],a:0,m:"Corect: A. Considerația = măsura în care un lider este abordabil și arată preocupare personală pentru subordonați (studiile Ohio State). Structurarea privește definirea sarcinilor și organizarea muncii."},
{q:"Factorii care influențează percepția sunt:",o:["observatorul, ținta, contextul","personalitatea, motivația, atitudinile","liderul, învățarea, contextul","ținta, observatorul, managerul"],a:0,m:"Corect: A. Factorii care influențează percepția: observatorul (atitudini, motive, experiență), ținta (caracteristicile obiectului perceput) și contextul (situația). B enumeră doar atribute ale observatorului, C și D amestecă elemente străine."},
{q:"Procesul de control managerial reunește următoarele faze: a) compararea performanței realizate cu standardul; b) motivare, leadership și comunicare; c) evaluarea performanței resurselor umane; d) luarea de măsuri manageriale corective; e) măsurarea performantei realizate; f) motivarea complexă a angajaților; g) planificarea scopurilor și obiectivelor organizaționale.",o:["(b, c, f)","(a, d, e)","(e, f, g)","(c, d, e)"],a:1,m:"Corect: B. Procesul de control managerial are trei faze: măsurarea performanței realizate, compararea performanței cu standardul și luarea de măsuri manageriale corective → (a, d, e). Planificarea, motivarea și evaluarea RU aparțin altor funcții."},
{q:"Controlul performanței organizaționale vizează: a) comparații cu alte firme / cu media industriei; b) corectarea problemelor pe măsură ce apar; c) eficacitatea organizațională; d) folosirea măsurilor disciplinare; e) productivitatea organizațională.",o:["(b, d, e)","(a, b, d)","(a, c, e)","(c, d, e)"],a:2,m:"Corect: C. Controlul performanței organizaționale vizează productivitatea organizațională, eficacitatea organizațională și comparațiile cu alte firme/media industriei (clasamente) → (a, c, e)."},
{q:"Managementul lanțului valorii este:",o:["setul de activități organizaționale care adaugă valoare în fiecare pas al transformării materiilor prime în produs/serviciu finit","procesul de gestionare a secvențelor de activități și informații de-a lungul întregului lanț al valorii","procesul de transformare a resurselor în produse/servicii","un proces orientat spre eficiență, al cărui scop este de a reduce costurile și de a face organizația mai productivă"],a:1,m:"Corect: B. Managementul lanțului valorii = procesul de gestionare a secvențelor de activități și informații de-a lungul întregului lanț al valorii, orientat extern, spre valoarea pentru client. A definește lanțul valorii (nu managementul lui), D descrie managementul lanțului de aprovizionare (orientat intern, spre eficiență)."},
{q:"Abordarea strategică a lanțului valorii nu presupune: a) abordarea inflexibilă a proiectării posturilor; b) clarificarea de către manageri a așteptărilor privind rolul fiecărui angajat în lanțul valorii; c) instruirea continuă a angajaților; d) relații concurente între toți participanții; e) schimbarea radicală a proceselor organizaționale.",o:["(a, d)","(b, c, e)","(a, b, d)","(b, c)"],a:0,m:"Corect: A. Abordarea strategică a lanțului valorii presupune posturi flexibile și relații de colaborare/coordonare între participanți; deci NU presupune abordarea inflexibilă a proiectării posturilor și relații concurente între participanți → (a, d)."},
{q:"Manager strategic — metoda proporționalității. Matricea: S1=(900,1200,600); S2=(600,450,1800); S3=(1500,900,500); S4=(400,1500,900). Varianta decizională optimă va fi:",o:["S1","S2","S3","S4"],a:2,m:"Corect: C. Metoda proporționalității (Laplace — echiprobabilitate): se alege media profiturilor pe fiecare strategie. S1 = (900+1200+600)/3 = 900; S2 = (600+450+1800)/3 = 950; S3 = (1500+900+500)/3 ≈ 966,67; S4 = (400+1500+900)/3 ≈ 933,33. Maximul mediei → S3."},
{q:"Aceeași matrice de profituri (S1=(900,1200,600); S2=(600,450,1800); S3=(1500,900,500); S4=(400,1500,900)) — metoda optimistă. Varianta decizională optimă va fi:",o:["S1","S2","S3","S4"],a:1,m:"Corect: B. Metoda optimistă (maximax): se alege maximul din maximele fiecărei strategii. Max: S1 = 1200; S2 = 1800; S3 = 1500; S4 = 1500. Cel mai mare câștig posibil (1800) → S2."},
{q:"Aceeași matrice de profituri (S1=(900,1200,600); S2=(600,450,1800); S3=(1500,900,500); S4=(400,1500,900)) — metoda pesimistă. Varianta decizională optimă va fi:",o:["S1","S2","S3","S4"],a:0,m:"Corect: A. Metoda pesimistă (maximin, Wald): se alege maximul dintre minimele fiecărei strategii. Min: S1 = 600; S2 = 450; S3 = 500; S4 = 400. Cel mai bun dintre cele mai slabe rezultate (600) → S1."},
{q:"Aceeași matrice de profituri (S1=(900,1200,600); S2=(600,450,1800); S3=(1500,900,500); S4=(400,1500,900)) — metoda minimizării regretelor. Varianta decizională optimă va fi:",o:["S1","S2","S3","S4"],a:1,m:"Corect: B. Metoda minimizării regretelor (Savage): regret = maximul coloanei − valoarea. Maxime pe coloane: SC1=1500, SC2=1500, SC3=1800. Regrete maxime: S1 = max(600, 300, 1200) = 1200; S2 = max(900, 1050, 0) = 1050; S3 = max(0, 600, 1300) = 1300; S4 = max(1100, 0, 900) = 1100. Regretul maxim minim (1050) → S2."},
{q:"Aceeași matrice de profituri (S1=(900,1200,600); S2=(600,450,1800); S3=(1500,900,500); S4=(400,1500,900)) — metoda optimalității (α=0,7). Varianta decizională optimă va fi:",o:["S1","S2","S3","S4"],a:1,m:"Corect: B. Metoda optimalității (Hurwicz, α=0,7): H = α·max + (1−α)·min. S1 = 0,7·1200 + 0,3·600 = 1020; S2 = 0,7·1800 + 0,3·450 = 1395; S3 = 0,7·1500 + 0,3·500 = 1200; S4 = 0,7·1500 + 0,3·400 = 1170. Maxim → S2."},
{q:"Achiziție laptopuri — metoda utilității totale cu coeficienți de importanță diferiți (V1: C1=1,C2=8,C3=2; V2: C1=1.5,C2=12,C3=2.5; V3: C1=2,C2=4,C3=3; V4: C1=0.5,C2=6,C3=1.5; Kj=0.3/0.3/0.4). Varianta decizională optimă va fi:",o:["V1","V2","V3","V4"],a:1,m:"Corect: B. Metoda utilității totale: utilitățile se normalizează pe fiecare criteriu (1 pentru cea mai bună valoare, 0 pentru cea mai slabă; la greutate, minimul e cel mai bun) și se ponderează cu Kj. V1 = 0,3·0,33 + 0,3·0,5 + 0,4·0,67 ≈ 0,52; V2 = 0,3·0,67 + 0,3·1 + 0,4·0,33 ≈ 0,63; V3 = 0,3·1 + 0,3·0 + 0,4·0 = 0,30; V4 = 0,3·0 + 0,3·0,25 + 0,4·1 = 0,48. Utilitatea totală maximă → V2."},
{q:"Manager de proiect: succes cu alocare de fonduri 80%, fără alocare 15%. Cost variantă cu alocare: 5000 EURO. Penalități în caz de neintrare în grafic: 1000 EURO. Speranța netă privind costul variantei cu alocare de fonduri va fi:",o:["4000 EURO","1200 EURO","3800 EURO","5200 EURO"],a:3,m:"Corect: D. Speranța netă a costului = costul cert al alocării + penalitatea ponderată cu probabilitatea de eșec: 5000 + (1 − 0,8)·1000 = 5000 + 0,2·1000 = 5200 EURO."}
  ]
},

microeconomie: {
  label: "Microeconomie",
  color: "#1F4E79",
  questions: [
{q:"Presupunem că prețul unui bun scade cu 10%, iar cantitatea cerută pentru o anumită perioadă de timp crește cu 15%. În aceste condiții:",o:["veniturile încasate de producători scad","veniturile încasate de producători cresc","veniturile producătorilor nu sunt influențate de modificarea prețului și a cantității cerute","cheltuielile firmei cresc"],a:1,m:"Corect: B. Prețul scade cu 10%, cantitatea cerută crește cu 15% → cererea este elastică (|Ec| = 15/10 = 1,5 > 1). La cerere elastică, venitul total (P×Q) evoluează invers față de preț: 0,9 × 1,15 = 1,035, deci veniturile producătorilor cresc cu 3,5% (cap. 2 — Elasticitatea cererii)."},
{q:"O creştere a preţului cu 50% antrenează o creştere a cantităţii oferite dintr-un bun economic de la 10 la 20 bucăţi. Să se calculeze coeficientul de elasticitate al ofertei:",o:["1/4","1/2","1","2"],a:3,m:"Corect: D. Coeficientul de elasticitate al ofertei: Eo = (%ΔQ)/(%ΔP) = [(20−10)/10] / 0,5 = 100% / 50% = 2 (cap. 3 — Elasticitatea ofertei)."},
{q:"Alegeţi afirmaţia falsă:",o:["în general, cererea pentru bunurile de necesitate este mai puţin elastică decât cererea pentru bunurile de lux","dacă preţul şi venitul producătorilor sunt direct proporţionale, cererea este elastică","o perioadă lungă de timp de la modificarea preţului unui bun imprimă ofertei un caracter elastic","dacă preţul pentru un bun principal creşte, caeteris paribus, oferta de pe piaţa bunului secundar va spori (şi invers)"],a:1,m:"Corect: B (afirmația falsă). Când prețul și venitul total al producătorilor evoluează direct proporțional (cresc/scad împreună), cererea este INELASTICĂ, nu elastică — la cerere elastică relația preț-venit este inversă. A, C și D sunt afirmații adevărate din teoria elasticității (cap. 2 și 3)."},
{q:"Alegeţi răspunsul corect privind elasticitatea: a) coeficientul elasticităţii cererii pentru bunurile alimentare este mai mare pentru persoanele cu venituri mici; b) cererea pentru pasta de dinţi Colgate este inelastică; c) cererea pentru bunurile de strictă necesitate este inelastică; d) în condiţiile practicării unor preţuri mai scăzute, maximizarea profitului este posibilă numai în situaţia unei cereri elastice; e) elasticitatea cererii în funcţie de preţ este 2. La o creştere a preţului cu 15%, cantitatea cerută se modifică cu 40%; f) o perioadă scurtă de timp de la modificarea preţului bunului A, imprimă ofertei un caracter inelastic; g) gradul de substituire al bunurilor reprezintă un factor care nu determină elasticitatea cererii în funcţie de preţ.",o:["(a,c,d,f,g)","(a,b,d,e)","(a,c,d,f)","(b,d,f,g)"],a:2,m:"Corect: C — adevărate sunt (a, c, d, f). b este falsă: pasta de dinți Colgate are substituenți apropiați, deci cererea e elastică; e este falsă: la Ec = 2 și ΔP = 15%, cantitatea se modifică cu 30%, nu 40%; g este falsă: gradul de substituire ESTE un factor determinant al elasticității cererii."},
{q:"Pentru un consumator, utilitatea marginală a untului este Umgu= 40 – 5Qu, iar a pâinii Umgp= 20 – 3Qp, preţul untului Pu= 5, preţul pâinii Pp= 1. Venitul disponibil este 20 u.m. Calculaţi cantităţile de unt si pâine consumate în echilibru:",o:["Qu = 1 și Qp = 5","Qu = 3 și Qp = 5","Qu = 3 și Qp = 7","Qu = 1 și Qp = 7"],a:1,m:"Corect: B. Echilibrul consumatorului (abordarea cardinală, cap. 4.2): Umgu/Pu = Umgp/Pp și restricția bugetară 5Qu + 1·Qp = 20. Din (40−5Qu)/5 = (20−3Qp)/1 rezultă 8−Qu = 20−3Qp → Qu = 3Qp−12. Înlocuind în buget: 5(3Qp−12)+Qp = 20 → 16Qp = 80 → Qp = 5, Qu = 3. Verificare: 5·3+5 = 20 ✓."},
{q:"Utilitatea totală coincide cu cea marginală:",o:["pentru prima unitate consumată","numai în cazul consumatorului iraţional","la nivelul ultimei unităţi consumate","la nivelul pragului de saturaţie"],a:0,m:"Corect: A. Utilitatea totală coincide cu utilitatea marginală doar la prima unitate consumată: UT(1) = Umg(1), deoarece Umg = ΔUT, iar înainte de prima unitate UT = 0 (cap. 4)."},
{q:"Potrivit legii utilităţii marginale:",o:["utilitatea unei unităţi suplimentare dintr-un bun nu poate niciodată să crească","utilitatea marginală trebuie să fie întotdeauna negativă","utilitatea marginală trebuie să fie întotdeauna pozitivă","utilitatea marginală poate creşte la început, dar apoi trebuie să scadă"],a:0,m:"Corect: A. În formularea strictă a legii utilității marginale descrescânde (Gossen I) din curs: pe măsură ce consumul dintr-un bun continuă, utilitatea fiecărei unități suplimentare scade — deci utilitatea unei unități suplimentare nu poate niciodată să crească. B și C absolutizează greșit semnul utilității marginale (cap. 4)."},
{q:"Curba de indiferenţă semnifică:",o:["consum egal a două bunuri","utilitate egală din consumul a două combinaţii de bunuri","venit egal al consumatorului","preţuri egale a bunurilor consumate"],a:1,m:"Corect: B. Curba de indiferență reunește toate combinațiile de două bunuri care aduc consumatorului aceeași utilitate (utilitate egală) — abordarea ordinală a utilității (cap. 4.3)."},
{q:"Consumatorul dispune de un venit de 80 u.m., cheltuindu-l pe cumpărarea a 2 bunuri: bunul x la preţul de 5 u.m. şi bunul y la preţul de 4 u.m. Care combinaţie din cele indicate este inaccesibilă?",o:["x=16, y=0","x=11, y=9","x=8, y=10","x=8, y=8"],a:1,m:"Corect: B. Restricția bugetară: 5x + 4y ≤ 80. A: 5·16+0 = 80 ✓; C: 5·8+4·10 = 80 ✓; D: 5·8+4·8 = 72 ✓; B: 5·11+4·9 = 55+36 = 91 > 80 → combinație inaccesibilă (cap. 4 — constrângerea bugetară)."},
{q:"Consumatorul dispune de un venit de 8 u.m. Preţul bunul X este de 1 u.m., preţul bunului Y 0,5 u.m. Care dintre următoarele combinaţii se află pe linia bugetului?",o:["8x+1y","7x+1y","6x+6y","5x+6y"],a:3,m:"Corect: D. Linia bugetului: 1·x + 0,5·y = 8. A: 8+0,5 = 8,5; B: 7+0,5 = 7,5; C: 6+3 = 9; D: 5·1 + 6·0,5 = 5+3 = 8 ✓ — singura combinație care epuizează exact venitul (cap. 4)."},
{q:"Punctele la intersecţia liniei bugetului cu axele coordonatelor semnifică:",o:["consumatorul nu-şi cheltuieşte tot venitul","consumatorul îşi cheltuieşte tot venitul doar pentru un bun","consumatorul nu cheltuieşte absolut nimic","sunt puncte imposibil de atins de către consumator"],a:1,m:"Corect: B. Punctele de intersecție ale liniei bugetului cu axele reprezintă situațiile în care consumatorul își cheltuiește tot venitul pentru un singur bun (întreaga sumă pe bunul X, respectiv pe bunul Y) (cap. 4)."},
{q:"Când cantitatea consumată dintr-un bun creşte, utilitatea marginală pe care o aduce fiecare nouă doză consumată:",o:["creşte cu o rată descrescătoare","creşte cu o rată crescătoare","scade","rămâne constantă"],a:2,m:"Corect: C. Conform legii utilității marginale descrescânde: pe măsură ce cantitatea consumată dintr-un bun crește, utilitatea marginală adusă de fiecare nouă doză scade (cap. 4)."},
{q:"Funcţia cererii pentru telefoanele mobile este Q = 200-P iar pentru oferta Q = 20+P. La ce nivel al preţului se va constata un exces de cerere pe piaţa telefoanelor mobile?",o:["mai mare decât 80 unităţi monetare","egal cu 80 unităţi monetare","mai mare decât 90 unităţi monetare","mai mic decât 90 unităţi monetare"],a:3,m:"Corect: D. Echilibrul pieței: 200−P = 20+P → 2P = 180 → P* = 90. Excesul de cerere (cerere > ofertă) apare la orice preț mai mic decât prețul de echilibru, deci P < 90 u.m. (cap. 3.3)."},
{q:"Presupunem că oferta pentru produsul A este perfect elastică. Dacă cererea pentru acest produs creşte:",o:["preţul şi cantitatea de echilibru vor crește","preţul şi cantitatea de echilibru vor scădea","cantitatea de echilibru va creşte dar preţul nu se va modifica","preţul de echilibru va creşte dar cantitatea nu se va modifica"],a:2,m:"Corect: C. Oferta perfect elastică este o dreaptă orizontală la prețul dat. Creșterea cererii (deplasarea curbei la dreapta) mărește cantitatea de echilibru, dar prețul rămâne neschimbat (cap. 3)."},
{q:"În condiţiile în care coeficientul elasticităţii cererii în funcţie de venit este mai mare decât 1 şi venitul creşte, ponderea cheltuielilor pentru marfa X în cheltuielile totale:",o:["va creşte","se va reduce","ramâne constantă","nu se poate determina"],a:0,m:"Corect: A. Dacă elasticitatea cererii în funcție de venit > 1 (bun superior/de lux), cantitatea cerută crește procentual mai mult decât venitul, deci ponderea cheltuielilor pentru marfa X în cheltuielile totale crește (cap. 2.3)."},
{q:"Fie funcţia ofertei P = 3 + 2Qo şi funcţia cererii P = 9 – Qc: a) preţul şi cantitatea de echilibru; b) coeficientul elasticităţii cererii şi al ofertei în funcţie de preţ în punctul de echilibru; c) dacă preţul creşte, ce se va întâmpla cu venitul total?",o:["( a. 7 și 2; b. 3,5 și 1,75; c. scade )","( a. 7 și 2; b. 3,5 și 1,5; c. scade )","( a. 3 și 3; b. 0,5 și 1,75; c. crește )","( a. 7 și 2; b. 3,5 și 1,75; c. crește )"],a:0,m:"Corect: A. (a) Echilibru: 3+2Q = 9−Q → 3Q = 6 → Q* = 2, P* = 7. (b) Cererea: Q = 9−P → Ec = |dQ/dP|·P/Q = 1·7/2 = 3,5; Oferta: Q = (P−3)/2 → Eo = 0,5·7/2 = 1,75. (c) Cererea fiind elastică (3,5 > 1), creșterea prețului reduce venitul total → scade."},
{q:"În situaţia în care cererea pentru produsele agricole este inelastică:",o:["reducerea preţurilor determină o creştere a veniturilor încasate de producători","reducerea preţurilor determină o reducere a veniturilor producătorilor","creşterea preţurilor nu conduce la diferenţieri în veniturile producătorilor","procentul de reducere a preţurilor este mai mic decat cel de creştere a cererii"],a:1,m:"Corect: B. La cerere inelastică, cantitatea reacționează procentual mai puțin decât prețul; reducerea prețurilor nu este compensată de creșterea cantității, deci veniturile totale ale producătorilor se reduc (cap. 2.3)."},
{q:"Pentru un consumator raţional care are de ales între două bunuri în condiţiile constrângerii bugetare, modificarea preţului unuia dintre bunuri, caeteris paribus, va determina:",o:["deplasarea paralelă a liniei bugetului","modificarea pantei liniei bugetului","nu va modifica linia bugetului","deplasarea paralelă a liniei bugetului la dreapta"],a:1,m:"Corect: B. Modificarea prețului unui singur bun schimbă raportul prețurilor Px/Py, deci modifică panta liniei bugetului (rotire în jurul interceptei celuilalt bun). Deplasarea paralelă apare doar la modificarea venitului (cap. 4)."},
{q:"Care dintre factorii de mai jos determină creşterea sau scăderea cantităţii cerute la acelaşi nivel al preţului: a. posibilităţile de stocare a bunurilor; b. preferinţele cumpărătorilor; c. costul producţiei; d. evenimentele social-politice şi naturale; e. modificarea preţurilor altor bunuri; f. factori demografici; g. previziunile privind evoluţia pieţei.",o:["(b,d,e,f,g)","(b,e,f,g)","(a,b,c,e,f)","(a,b,d,e,f,g)"],a:1,m:"Corect: B. Factorii care deplasează cererea la același nivel al prețului (condițiile cererii): preferințele cumpărătorilor, prețurile altor bunuri, factorii demografici și previziunile privind evoluția pieței → (b, e, f, g). Posibilitățile de stocare și costul producției sunt factori ai ofertei (cap. 2.1)."},
{q:"Preţul produsului A s-a redus de la 100 la 90 lei şi, ca urmare, cantitatea cerută a crescut de la 70 la 75 unităţi. Cererea este:",o:["inelastică","elastică","cu elasticitate unitară","nu poate fi determinată din informaţia dată"],a:0,m:"Corect: A. |Ec| = (%ΔQ)/(%ΔP) = (5/70)/(10/100) = 7,14%/10% ≈ 0,71 < 1 → cerere inelastică (cap. 2.3)."},
{q:"În situaţia în care costul fix mediu în perioada 0 al unei firme este 30.000 lei. La un spor al producţiei de 50%, costul fix mediu în perioada 1 devine:",o:["15.000 lei","30.000 lei","20.000 lei","45.000 lei"],a:2,m:"Corect: C. CFM = CF/Q. Costul fix total rămâne constant: CF = 30.000·Q0. La Q1 = 1,5·Q0: CFM1 = CF/Q1 = 30.000/1,5 = 20.000 lei (cap. 7 — Analiza costurilor)."},
{q:"Efectul de substituire constă în: a. creşterea preţurilor la bunurile substituibile unui bun dat; b. creşterea cantităţii cerute din alte bunuri, ale căror preţuri nu au crescut; c. reducerea venitului real şi deci, orientarea consumatorilor spre bunuri inferioare; d. reprezintă unul din cele două efecte generale ale creşterii preţului unui anumit bun.",o:["(a,b)","(a)","(b,d)","(c,d)"],a:2,m:"Corect: C. Efectul de substituire (una dintre cele două componente ale efectului creșterii prețului unui bun, alături de efectul de venit): consumatorii cresc cantitatea cerută din alte bunuri, ale căror prețuri nu au crescut → (b, d) (cap. 2.2)."},
{q:"Un agent economic depune la o bancă o sumă de 10.000 lei cu o rată a dobânzii de 5%. Care va fi suma existentă în bancă după 2 ani dacă agentul economic nu execută retrageri din contul creat în această perioadă?",o:["11.000 lei","1.000 lei","11.025 lei","500 lei"],a:2,m:"Corect: C. Dobândă compusă: S = 10.000·(1+0,05)² = 10.000·1,1025 = 11.025 lei după 2 ani fără retrageri (cap. 6.1 — Dobânda)."},
{q:"În cazul în care curba cererii pentru produsul A se deplasează la dreapta, iar preţul pentru produsul B scade, se poate concluziona că:",o:["A şi B sunt substituibile","A şi B sunt bunuri complementare","A este un bun inferior, iar B este un bun superior","Ambele bunuri A şi B sunt inferioare"],a:1,m:"Corect: B. A și B sunt bunuri complementare: scăderea prețului lui B mărește cantitatea cerută din B și, în consecință, crește cererea pentru A (deplasare la dreapta a curbei cererii lui A). La substituibile, efectul ar fi invers (cap. 2.1)."},
{q:"Preţul unui bun este de 400 u.m., iar cantitatea cerută din acel bun este de 1000 bucăţi. Previziunile pieţei se îndeplinesc și preţul scade la 360 u.m. Care ar fi reacţia cantităţii cerute pentru a ne regăsi în situaţia unui bun cu cerere inelastică?",o:["scade cu mai puţin de 10%","creşte cu mai mult de 10%","scade cu mai mult de 10%","creşte cu mai puţin de 10%"],a:3,m:"Corect: D. Prețul scade cu 10% (400→360). Pentru cerere inelastică, |%ΔQ| < |%ΔP|, iar preț și cantitate evoluează în sens opus → cantitatea cerută crește cu mai puțin de 10% (cap. 2.3)."},
{q:"Capitalul circulant: a) se amortizează; b) este profund transformat în cursul procesului de producţie; c) se înlocuieşte după mai mulţi ani de utilizare; d) are ca şi componentă, printre altele, combustibilul.",o:["(a,b)","(b,c)","(c,d)","(b,d)"],a:3,m:"Corect: D. Capitalul circulant este profund transformat în cursul procesului de producție (se consumă integral într-un singur ciclu) și include materii prime, materiale, combustibil → (b, d). Amortizarea și înlocuirea după mai mulți ani caracterizează capitalul fix (cap. 5)."},
{q:"Care din următoarele aspecte delimitează capitalul fix de cel circulant: a) numărul de cicluri de producţie la care participă; b) locul de desfăşurare a activităţii de producţie; c) perioada după care se înlocuiesc; d) modalitatea de transmitere a valorii sale asupra noului produs.",o:["(a,d)","(c,d)","(a,c,d)","(b,c,d)"],a:2,m:"Corect: C. Capitalul fix se delimitează de cel circulant prin: numărul de cicluri de producție la care participă, perioada după care se înlocuiește și modalitatea de transmitere a valorii asupra noului produs (integral vs treptat, prin amortizare) → (a, c, d). Locul de desfășurare nu e criteriu (cap. 5)."},
{q:"Capitalul tehnic consumat este egal cu: a) valoarea mijloacelor de producţie consumate; b) capitalul fix utilizat plus capitalul circulant; c) capitalul circulant consumat plus capitalul fix folosit; d) capitalul circulant utilizat plus amortizarea capitalului fix.",o:["(b,c)","(a,d)","(c)","(a)"],a:1,m:"Corect: B. Capitalul tehnic consumat = valoarea mijloacelor de producție consumate = capitalul circulant utilizat + amortizarea capitalului fix → (a, d). Capitalul fix nu se consumă integral, ci doar cota de amortizare (cap. 5)."},
{q:"Valoarea capitalului utilizat într-o firmă este de 30.000 u.m. din care 16.000 u.m. reprezintă capital circulant. Capitalul consumat fiind de 20.000 u.m., valoarea capitalului neamortizat după un an este:",o:["10.000 u.m.","12.000 u.m.","20.000 u.m.","18.000 u.m."],a:0,m:"Corect: A. Capital fix = 30.000 − 16.000 = 14.000 u.m. Capital consumat = 20.000 = capital circulant (16.000, consumat integral) + amortizare (4.000). Capital fix neamortizat = 14.000 − 4.000 = 10.000 u.m. (cap. 5, 7)."},
{q:"La o societate comercială: costuri materiale 89 mil.; capital circulant 45 mil.; salarii indirecte 10 mil.; costuri fixe 90 mil.; costuri variabile 52 mil. Să se calculeze costurile materiale fixe şi amortizarea:",o:["60 şi 64","70 şi 56","80 şi 44","89 şi 45"],a:2,m:"Corect: C. Costurile materiale fixe = CF − salarii indirecte = 90 − 10 = 80 mil. Amortizarea = costuri materiale − capital circulant consumat = 89 − 45 = 44 mil. → „80 și 44” (cap. 7)."},
{q:"Fiind dată relaţia CTM = 20Q (CTM – costul total mediu, Q – producţia), costul marginal al celei de-a cincea unităţi de producţie este:",o:["200","100","4","6"],a:0,m:"Corect: A. CTM = 20Q → CT = CTM·Q = 20Q². Costul marginal: Cmg = dCT/dQ = 40Q. La Q = 5: Cmg = 40·5 = 200 (cap. 7.2)."},
{q:"În componenţa costului fix se includ: a) cheltuielile cu salariile personalului administrativ; b) cheltuielile cu amortizarea capitalului fix; c) costurile cu energia pentru fabricaţie; d) cheltuielile cu iluminatul general.",o:["(a,b,c)","(a,b,d)","(a,c,d)","(b,c,d)"],a:1,m:"Corect: B. Costul fix include cheltuieli independente de volumul producției: salariile personalului administrativ, amortizarea capitalului fix, iluminatul general → (a, b, d). Energia pentru fabricație variază cu producția → cost variabil (cap. 7)."},
{q:"Într-o firmă producţia înregistrată scade cu 40%. Cum se modifică CFM?",o:["scade cu 60%","scade cu 40%","creşte cu 66,66%","nu se modifică"],a:2,m:"Corect: C. CFM = CF/Q. La Q' = 0,6Q (scădere cu 40%): CFM' = CF/(0,6Q) = CFM/0,6 ≈ 1,6666·CFM → CFM crește cu 66,66% (cap. 7)."},
{q:"Când volumul producţiei este zero: a) costul fix este 0; b) costul variabil este 0; c) costul fix este mai mare decât costul variabil; d) costul variabil este mai mare decât costul fix.",o:["(a,b,c)","(b,c,d)","(b,c)","(a,d)"],a:2,m:"Corect: C. La Q = 0: costul variabil este 0 (nu se produce nimic), iar costul fix rămâne pozitiv (chirii, amortizare), deci CF > CV → (b, c). Afirmația (a) e falsă — costul fix nu dispare la producție zero (cap. 7)."},
{q:"Să se calculeze CFM, pentru un nivel al producţiei Q = 20, ştiind că funcţia costului total este: CT = 200 + 3Q + 2Q².",o:["1060","200","20","10"],a:3,m:"Corect: D. Din CT = 200 + 3Q + 2Q², componenta fixă (independentă de Q) este CF = 200. CFM = CF/Q = 200/20 = 10 (cap. 7.2)."},
{q:"Care dintre următoarele afirmaţii este falsă:",o:["Concurenţa perfectă presupune mulţi vânzători de produse standardizate","Concurenţa monopolistică presupune mulţi vânzători de produse omogene","Oligopolul presupune câţiva producători de bunuri standardizate sau diferenţiate","Monopolul presupune un singur produs pentru care nu există substitute apropiate"],a:1,m:"Corect: B (afirmația falsă). Concurența monopolistică presupune mulți vânzători de produse DIFERENȚIATE, nu omogene — diferențierea produsului este chiar trăsătura ei definitorie. A, C, D descriu corect concurența perfectă, oligopolul și monopolul (cap. 8)."},
{q:"Pe piaţa cu concurenţă perfectă:",o:["Firma este un „price–taker”, adică preia preţul stabilit pe piaţă","Firma este un „price–maker”, adică stabileşte preţul pe piaţă","Produsele firmelor sunt diferenţiate","Barierele de intrare sunt minime, iar cele de ieşire de pe piaţă sunt maxime"],a:0,m:"Corect: A. Pe piața cu concurență perfectă firma este „price-taker”: preia prețul stabilit de piață prin confruntarea cererii totale cu oferta totală, fiind prea mică pentru a-l influența. Produsele sunt omogene, iar barierele de intrare/ieșire sunt minime (cap. 8.3)."},
{q:"Care dintre condiţiile următoare indică faptul că un bun este produs în condiţii de concurenţă perfectă:",o:["profiturile producătorilor sunt mari","profiturile producătorilor sunt mici","oferta totală este inelastică","cererea individuală este perfect elastică"],a:3,m:"Corect: D. În concurență perfectă, firma individuală poate vinde orice cantitate la prețul pieței → cererea individuală (percepută de firmă) este perfect elastică (orizontală). Nivelul profiturilor nu indică tipul de piață (cap. 8.3)."},
{q:"Curba cererii pe o piaţă cu concurenţă monopolistică este:",o:["perfect elastică","descrescătoare","perfect inelastică","crescătoare"],a:1,m:"Corect: B. În concurența monopolistică produsele sunt diferențiate, deci fiecare firmă are o putere limitată asupra prețului → curba cererii firmei este descrescătoare (nu orizontală ca în concurența perfectă) (cap. 8.4)."},
{q:"Condiţia de maximizare a profitului în cazul unei firme pe o piaţă cu concurenţă monopolistică este (Vmg venit marginal, Cmg cost marginal, P preţ, CTM cost mediu, VT venituri totale):",o:["Vmg = Cmg","Cmg = P","Vmg = CTM","VT să fie maxim"],a:0,m:"Corect: A. Condiția generală de maximizare a profitului, valabilă și în concurența monopolistică: venitul marginal egal cu costul marginal (Vmg = Cmg). Cmg = P este cazul particular al concurenței perfecte (cap. 8.4)."},
{q:"Care dintre următoarele afirmaţii cu privire la monopol sunt adevărate:",o:["Există mai multe firme producătoare a unui produs specific","Există o singură firmă producătoare, dar produsul are substitute apropiate","Nu există competitori pe piaţa relevantă","Barierele de intrare sunt reduse"],a:2,m:"Corect: C. Monopolul: un singur producător pe piața relevantă, fără competitori, produs fără substitute apropiate, bariere de intrare ridicate — deci C este adevărată, iar A, B, D contrazic definiția (cap. 8.5)."},
{q:"Între concurenţa monopolistică şi cea perfectă există diferenţe privind:",o:["intrarea pe piaţă","numărul de vânzători şi cumpărători","puterea de piaţă a competitorilor","omogenitatea produselor"],a:3,m:"Corect: D. Concurența monopolistică se aseamănă cu cea perfectă la numărul mare de vânzători și intrarea liberă; diferența esențială este omogenitatea produselor — omogene la concurența perfectă, diferențiate la cea monopolistică (cap. 8.4)."},
{q:"O firmă are funcţia costului total CT(Q) = 125 + 4Q². Determinaţi cantitatea şi preţul care maximizează profitul total dacă firma acţionează pe o piaţă de monopol şi funcţia cererii este P = 100 – Q.",o:["Q = 10, P = 90","Q = 20, P = 80","Q = 5, P = 95","Q = 15, P = 100"],a:0,m:"Corect: A. Monopol: VT = P·Q = (100−Q)·Q = 100Q−Q² → Vmg = 100−2Q; Cmg = dCT/dQ = 8Q. Vmg = Cmg: 100−2Q = 8Q → Q = 10; P = 100−10 = 90 (cap. 8.5)."},
{q:"Care dintre următoarele pot fi considerate trăsăturile de bază ale bunurilor publice:",o:["se află în proprietatea statului","se caracterizează prin non–excluziune şi non-rivalitate","se caracterizează prin rivalitate şi excluziune","pot fi pozitive sau negative"],a:1,m:"Corect: B. Trăsăturile de bază ale bunurilor publice: non-excluziunea (nimeni nu poate fi exclus de la consum) și non-rivalitatea (consumul unuia nu reduce consumul altora). Proprietatea statului nu e criteriu definitoriu (cap. 9)."},
{q:"Care dintre următoarele soluţii nu fac parte dintre căile de internalizare a externalităţilor:",o:["practicarea unor amenzi plătite de producătorul de externalităţi negative","introducerea de taxe şi impozite care să aducă costurile private la nivelul celor sociale","închiderea firmelor producătoare de externalităţi pozitive sau negative","unirea producătorului de externalitate negativă cu receptorul unui asemenea efect"],a:2,m:"Corect: C. Căile de internalizare a externalităților: amenzi, taxe și impozite pigouviene, unirea producătorului cu receptorul efectului. Închiderea firmelor NU este o cale de internalizare — mai ales că externalitățile pozitive sunt de încurajat (cap. 9.3)."},
{q:"Care dintre următorii economişti a afirmat că problema externalităţilor poate fi rezolvată, în anumite condiţii, fără intervenţie guvernamentală:",o:["A.C. Pigou","Marshall","V. Pareto","R. Coase"],a:3,m:"Corect: D. Ronald Coase a demonstrat (teorema Coase) că problema externalităților poate fi rezolvată prin negociere privată, fără intervenție guvernamentală, dacă drepturile de proprietate sunt bine definite și costurile de tranzacție sunt reduse (cap. 9)."},
{q:"Dacă o activitate economică se concretizează în producerea a două bunuri, unul ce generează externalităţi pozitive şi altul care generează externalităţi negative, consecinţele pe piaţă vor fi:",o:["producţie prea mare pentru bunul ce generează externalităţi pozitive şi o producţie prea mică pentru bunul ce generează externalităţi negative","producţie prea mică pentru bunul ce generează externalităţi pozitive şi o producţie prea mare pentru bunul ce generează externalităţi negative","producţie prea mică pentru ambele bunuri","producţie prea mare pentru ambele bunuri"],a:1,m:"Corect: B. Piața ignoră beneficiile/costurile externe: bunul cu externalități pozitive se produce prea puțin (beneficiul social > beneficiul privat), iar bunul cu externalități negative se produce prea mult (costul social > costul privat) (cap. 9.2)."},
{q:"Tabel: Telefoane: A=0, B=8, C=16, D=24, E=32; Calculatoare: A=18, B=14, C=9, D=5, E=0. Care este costul de oportunitate (în unități monetare) al unui telefon prin mișcarea de la B la C, dacă prețul unui calculator este de 280 euro?",o:["1050","220","175","200"],a:2,m:"Corect: C. Trecerea B→C: telefoanele cresc cu 8 (8→16), calculatoarele scad cu 5 (14→9). Costul de oportunitate al unui telefon = 5/8 calculatoare = 0,625 × 280 euro = 175 euro (cap. 1.2 — curba posibilităților de producție)."},
{q:"În mod normal, economia naturală se caracterizează prin:",o:["formarea preţurilor prin mecanisme complexe","concurenţa perfectă","preponderenţa schimbului de produse","satisfacerea nevoilor comunităţii şi individului din producţie proprie"],a:3,m:"Corect: D. Economia naturală se caracterizează prin satisfacerea nevoilor comunității și individului din producția proprie (autoconsum); schimbul și mecanismele complexe de preț definesc economia de schimb/de piață (cap. 1.3)."},
{q:"Care dintre trăsăturile de mai jos definesc trebuințele umane:",o:["nu sunt concurente","nu se sting momentan prin satisfacere","sunt nelimitate în capacitate","sunt nelimitate ca număr"],a:3,m:"Corect: D. Trăsăturile trebuințelor umane: sunt nelimitate ca număr, limitate în capacitate, concurente (unele se extind în detrimentul altora) și se sting momentan prin satisfacere (se regenerează). Singura afirmație corectă este D (cap. 1.2)."}
  ]
},

managementOperational: {
  label: "Management operațional",
  color: "#7A4419",
  questions: [
{q:"Tabloul de bord, folosit ca instrument în management: a) reprezintă instrument de clasificare a clientelei; b) regrupează și prezintă sub formă selectivă indicatorii semnificativi denumiți și puncte cheie sau semnalizatori, care permit responsabilului ansamblului sau al unei părți a firmei să-și controleze propriul domeniu de responsabilitate; c) este un instrument de lucru, de control, de previziune, de planificare a unor acțiuni legate de un domeniu de responsabilitate din cadrul firmei; d) este un instrument folosit pentru ordonanțarea producției.",o:["(b, c)","(a, b)","(d)","(a, d)"],a:0,m:"Corect: A (b, c). Conform suportului de curs, tabloul de bord regrupează și prezintă selectiv indicatorii semnificativi (puncte cheie/semnalizatori) și este un instrument de lucru, control, previziune și planificare pentru un domeniu de responsabilitate. Nu clasifică clientela și nu servește la ordonanțarea producției."},
{q:"Tabloul de bord al managerului cuprinde următoarele părți: a) Elemente ale activității comerciale; b) Elemente consacrate sintezei bugetului de exploatare; c) Elemente care evidențiază mijloacele firmei; d) Elemente care reflectă evoluția trezoreriei.",o:["(b, c)","(a, b, c, d)","(a, d)","(a, c, d)"],a:1,m:"Corect: B (a, b, c, d). Tabloul de bord al managerului cuprinde toate cele patru părți: elemente ale activității comerciale, sinteza bugetului de exploatare, mijloacele firmei și evoluția trezoreriei."},
{q:"Identificați afirmațiile corecte: a) Centrul de cheltuieli o parte din structura formală a firmei pentru care cheltuielile pot fi identificate; b) Centrul de profit este o extindere a structurii formale a firmei, unde nu numai cheltuielile, dar și profiturile sunt identificabile; c) Centrul de profit reprezintă acea parte a afacerii generatoare de cheltuieli și de venituri; d) Centrul de buget este reprezentat de un segment al unei firme asupra căreia se poate exercita un control și pentru care se poate elabora un buget.",o:["(b, c)","(a, b)","(a, b, c, d)","(a, d)"],a:2,m:"Corect: C (a, b, c, d). Toate afirmațiile sunt corecte conform cursului: centrul de cheltuieli — parte a structurii formale cu cheltuieli identificabile; centrul de profit — extindere unde și profiturile sunt identificabile, generatoare de cheltuieli și venituri; centrul de buget — segment controlabil pentru care se poate elabora un buget."},
{q:"După criteriul sferei de cuprindere se disting următoarele tipuri de bugete: a) bugete generale; b) bugete parțiale; c) bugete elaborate pe compartimente (funcționale sau operaționale) și pe posturi de conducere; d) bugete elaborate pe produse, proiecte sau activități, întocmite în funcție de timpul necesar realizării produsului, proiectului sau activității respective.",o:["(b, c)","(a, b)","(b, d)","(a, d)"],a:1,m:"Corect: B (a, b). După criteriul sferei de cuprindere, bugetele sunt generale și parțiale. Bugetele pe compartimente/posturi și cele pe produse/proiecte/activități se disting după criteriul responsabilității bugetare, respectiv al periodicității."},
{q:"După criteriul responsabilității bugetare se disting următoarele tipuri de bugete: a) bugete generale; b) bugete elaborate pe compartimente (funcționale sau operaționale) și pe posturi de conducere; c) bugete elaborate pe produse, proiecte sau activități, întocmite în funcție de timpul necesar realizării produsului, proiectului sau activității respective; d) bugete parțiale.",o:["(b, c)","(a, b)","(a, c, d)","(a, d)"],a:0,m:"Corect: A (b, c). După criteriul responsabilității bugetare se disting: bugete elaborate pe compartimente (funcționale sau operaționale) și pe posturi de conducere, respectiv bugete pe produse, proiecte sau activități. Generale/parțiale țin de sfera de cuprindere."},
{q:"Prognoza reprezintă pentru manager:",o:["anticipare a unor evenimente viitoare","judecată în baza unei experiențe de viață","capacitate de a enunța o teorie care se bazează pe previziune","opinie formată pe baza propriei capacități"],a:0,m:"Corect: A. Prognoza reprezintă pentru manager anticiparea unor evenimente viitoare, pe baze științifice — fundament al funcției de previziune. Judecata din experiență sau opinia proprie nu definesc prognoza."},
{q:"Planul de fabricație este un tablou care are următoarele caracteristici: a) este componentă a previziunilor livrărilor de piese fabricate ale unui atelier sau post de lucru; b) asigură corespondența acestor previziuni ale livrărilor cu previziunile legate de activitatea de fabricație și cu numărul de ore solicitate de aceasta pe post de lucru; c) asigură echilibrul între volumul de muncă necesar și cel repartizat diverselor posturi de lucru (sau atelierelor de fabricație); d) stabilește cheltuielile în ore pentru fiecare atelier și distribuie posturile de lucru în funcție de producția ce trebuie obținută, pe lună și pe zi.",o:["(b, c)","(a, b)","(d)","(a, b, c, d)"],a:3,m:"Corect: D (a, b, c, d). Planul de fabricație are toate caracteristicile enumerate: componentă a previziunilor livrărilor, asigură corespondența cu previziunile de fabricație și orele pe post, echilibrează volumul de muncă necesar cu cel repartizat și stabilește cheltuielile în ore pe ateliere, pe lună și pe zi."},
{q:"Întocmirea planului de fabricație în funcție de necesarul de livrat este un proces complex, care presupune următoarele activități: a) responsabilul cu producția întocmește planul de producție pe baza consumului de timp exprimat în ore-mașină sau ore-om, care apoi este transmis fiecărui șef de atelier; b) șeful de atelier decide cantitatea de materie primă necesară zilnic; c) fiecare șef de atelier calculează la rândul său timpul (exprimat în ore-om sau ore-mașină) necesar realizării programului de fabricație care i-a fost transmis.",o:["(b)","(a, c)","(a, b, c)","(a, b)"],a:1,m:"Corect: B (a, c). Procesul presupune: responsabilul cu producția întocmește planul pe baza consumului de timp (ore-mașină/ore-om) și îl transmite șefilor de atelier, iar fiecare șef de atelier calculează timpul necesar realizării programului primit. Decizia zilnică privind materia primă (b) nu face parte din acest proces."},
{q:"Diminuarea numărului lansărilor de produse în fabricație are următorul efect direct:",o:["reduce timpul de întocmire a bugetului comercial","construirea de procese tehnologice comune","reduce întreruperile în activitatea diverselor posturi de muncă și determină o reducere a timpilor de pregătire - încheiere aferenți fiecărui post de lucru","crește costurile de producție"],a:2,m:"Corect: C. Diminuarea numărului lansărilor de produse în fabricație reduce întreruperile în activitatea posturilor de muncă și determină o reducere a timpilor de pregătire-încheiere aferenți fiecărui post de lucru — efect direct asupra continuității fabricației."},
{q:"Întocmirea planurilor de fabricație revine și șefilor de echipă care detaliază planificarea procesului de fabricație prin: a) întocmirea fișei postului; b) programarea procesului de fabricație pe echipe; c) programarea activității de fabricație pe postul de muncă; d) elaborarea unui model de lucru.",o:["(b, c)","(a, b)","(c, d)","(a, d)"],a:0,m:"Corect: A (b, c). Șefii de echipă detaliază planificarea procesului de fabricație prin programarea procesului de fabricație pe echipe și programarea activității de fabricație pe postul de muncă. Fișa postului și modelele de lucru nu țin de această detaliere."},
{q:"Elaborarea bugetului mașinilor și utilajelor, nu poate fi separată de planificarea pentru posturi de fabricație, deoarece: a) se corelează necesarul de energie electrică; b) ajută la calcularea tactului; c) se verifică astfel dacă mașinile și instalațiile existente sunt suficiente pentru executarea programului de fabricație; d) se verifică astfel dacă programul întocmit este compatibil cu structura mașinilor și utilajelor din dotarea atelierului sau secției de producție.",o:["(b, c)","(a, b)","(c, d)","(a, d)"],a:2,m:"Corect: C (c, d). Bugetul mașinilor și utilajelor nu poate fi separat de planificarea posturilor de fabricație deoarece astfel se verifică dacă mașinile și instalațiile existente sunt suficiente pentru executarea programului și dacă programul este compatibil cu structura utilajelor din dotare."},
{q:"Dacă exigențele cerute de întocmirea bugetului mașinilor și utilajelor nu sunt satisfăcute, se va acționa, după caz, în următoarele direcții: a) reconsiderarea planificării producției; b) reechilibrarea volumului de muncă între posturile de lucru; c) efectuarea unei modificări a programului de lucru; d) angajarea de personal suplimentar pe anumite posturi de lucru pentru care forța de muncă este deficitară.",o:["(c, d)","(a, b)","(a, b, c, d)","(a, d)"],a:2,m:"Corect: C (a, b, c, d). Dacă exigențele bugetului mașinilor și utilajelor nu sunt satisfăcute, se acționează în toate cele patru direcții: reconsiderarea planificării producției, reechilibrarea volumului de muncă între posturi, modificarea programului de lucru și angajarea de personal suplimentar pe posturile deficitare."},
{q:"Dacă în ultimă instanță apar anumite neconcordanțe între planul de fabricație și posibilitățile reale de fabricație din atelier, atunci: a) se reconsideră întregul proces de planificare și se întocmește un nou plan de fabricație care este rezultatul unui proces iterativ; b) se realizează aprovizionarea cu materiale în plus și se achiziționează mașini noi și se întocmește un nou plan de fabricație care este rezultatul unui proces iterativ; c) se renunță la contractul încheiat cu beneficiarul.",o:["(c)","(a, b)","(a, b, c)","(a)"],a:1,m:"Corect: B (a, b). La neconcordanțe între planul de fabricație și posibilitățile reale ale atelierului, fie se reconsideră întregul proces de planificare (proces iterativ), fie se realizează aprovizionare suplimentară și investiții în mașini noi, urmate de un nou plan. Renunțarea la contract nu este o soluție prevăzută de curs."},
{q:"Planul de fabricație se concretizează: a) pentru executant (șeful de echipă) în planificarea pe post de lucru a activității muncitorului; b) pentru șeful de atelier, în planificarea activității de fabricație a atelierului; c) pentru șeful de secție, în planificarea atelierelor; d) pentru directorul cu producția, în planificarea secțiilor.",o:["(c, d)","(a, b)","(a, c, d)","(a, b, c, d)"],a:3,m:"Corect: D (a, b, c, d). Planul de fabricație se concretizează pe toate nivelurile ierarhice: pentru șeful de echipă — planificarea pe post de lucru; pentru șeful de atelier — planificarea atelierului; pentru șeful de secție — planificarea atelierelor; pentru directorul cu producția — planificarea secțiilor."},
{q:"Activitatea de planificare a fabricației necesită efectuarea unor consumuri: a) consumuri de manoperă directă și indirectă; b) consumuri de materii prime și materiale consumabile; c) efectuarea unor cheltuieli de fabricație; d) planificarea cheltuielilor cu publicitatea.",o:["(a, c, d)","(a, b)","(a, b)","(a, b, c)"],a:3,m:"Corect: D (a, b, c). Planificarea fabricației necesită consumuri de manoperă directă și indirectă, consumuri de materii prime și materiale consumabile și efectuarea unor cheltuieli de fabricație. Cheltuielile cu publicitatea aparțin bugetului comercial, nu planificării fabricației."},
{q:"Întocmirea bugetului forței de muncă ocupată în procesul de fabricație, se realizează în două etape: a) stabilirea bugetului forței de muncă exprimat în ore-manoperă; b) atribuirea sarcinilor la fiecare post de lucru; c) determinarea bugetului forței de muncă exprimat în unități valorice.",o:["(b, c)","(a, b)","(a, c)","(a)"],a:2,m:"Corect: C (a, c). Bugetul forței de muncă ocupate în fabricație se realizează în două etape: stabilirea bugetului exprimat în ore-manoperă și determinarea bugetului exprimat în unități valorice. Atribuirea sarcinilor pe posturi nu este o etapă a bugetării."},
{q:"Stabilirea bugetului forței de muncă exprimat în ore-manoperă, are finalitatea în:",o:["bugetul orelor de manoperă - un tablou al repartizării orelor de manoperă, în cadrul procesului de planificare, pe fiecare verigă organizatorică","determinarea bugetului forței de muncă exprimat în unități valorice (costurile aferente orelor de manoperă)","nici una dintre variante","ambele variante"],a:0,m:"Corect: A (a). Stabilirea bugetului forței de muncă exprimat în ore-manoperă are finalitatea în bugetul orelor de manoperă — tabloul repartizării orelor de manoperă pe fiecare verigă organizatorică. Exprimarea valorică este etapa următoare, distinctă."},
{q:"Metoda O.P.T. (Technologie Production Optimisee) are ca obiective: a) reducerea stocurilor; b) creșterea producției vândute; c) creșterea intensității muncii; d) diminuarea cheltuielilor de exploatare.",o:["(c, d)","(a, b, d)","(a, c, d)","(a, d)"],a:1,m:"Corect: B (a, b, d). Obiectivele metodei O.P.T.: reducerea stocurilor, creșterea producției vândute și diminuarea cheltuielilor de exploatare. Creșterea intensității muncii nu este un obiectiv al metodei."},
{q:"Întocmirea bugetului materiilor prime: a) se face în expresie fizică; b) se face în unități valorice; c) se face în unități calitative.",o:["(c)","(a, b)","(a, c)","(a, b, c)"],a:1,m:"Corect: B (a, b). Bugetul materiilor prime se întocmește în expresie fizică (cantitativă) și în unități valorice. Nu există exprimare „în unități calitative”."},
{q:"Bugetul materiilor prime în expresie fizică: a) are la bază planul de fabricație întocmit care stabilește cantitățile de produse de fabricat; b) stabilește necesarul de resursă de muncă; c) fixează operațiile de executat în cadrul fiecărei secții, fiecărui atelier, fiecărei echipe și fiecărui post de lucru.",o:["(c)","(b)","(a, b)","(a, c)"],a:3,m:"Corect: D (a, c). Bugetul materiilor prime în expresie fizică are la bază planul de fabricație (care stabilește cantitățile de produse) și fixează operațiile de executat pe secții, ateliere, echipe și posturi de lucru. Necesarul de resursă de muncă (b) face obiectul bugetului forței de muncă."},
{q:"Bugetul materiilor prime în expresie fizică conține: a) consumuri materiale detaliate, conform procesului de planificare, pe posturi de muncă; b) atât consumul propriu-zis, cât și deșeurile sau pierderile de fabricație; c) consumuri materiale detaliate la care se adaugă 20% în plus.",o:["(a, b)","(a)","(b, c)","(a, c)"],a:0,m:"Corect: A (a, b). Bugetul materiilor prime în expresie fizică conține consumurile materiale detaliate pe posturi de muncă, incluzând atât consumul propriu-zis, cât și deșeurile sau pierderile de fabricație. Nu se adaugă un procent forfetar de 20%."},
{q:"Rebuturile și deșeurile de fabricație: a) sunt luate în calcul în cadrul bugetelor de fabricație, deoarece cantitatea de materiale consumate împreună cu deșeurile trebuie să conducă la un număr egal cu cel al produselor fabricate, care este diminuat cu rebuturile; b) nu sunt luate în calcul în cadrul bugetelor de fabricație; c) necesită întocmirea unui buget special pentru pierderi și rebuturi dacă au o pondere importantă din cantitățile consumate; d) nu necesită întocmirea unui buget special pentru pierderi și rebuturi dacă au o pondere importantă din cantitățile consumate.",o:["(c, d)","(a, b)","(a, b, c, d)","(a, c)"],a:3,m:"Corect: D (a, c). Rebuturile și deșeurile sunt luate în calcul în bugetele de fabricație (materialele consumate + deșeurile trebuie să corespundă numărului de produse, diminuat cu rebuturile), iar dacă au o pondere importantă din cantitățile consumate, necesită întocmirea unui buget special de pierderi și rebuturi."},
{q:"Bugetul materiilor prime în expresie valorică: a) constă în exprimarea valorică a bugetului materiilor prime; b) se obține prin multiplicarea cifrelor din bugetul cantitativ în expresie fizică cu prețul fiecărui material consumat; c) se obține prin multiplicarea cifrelor din bugetul cantitativ în expresie fizică cu costurile standard unitare ale fiecărui material consumat; d) ține cont de valoarea de întrebuințare a produsului final.",o:["(c, d)","(a, c)","(a, b, c, d)","(a, d)"],a:1,m:"Corect: B (a, c). Bugetul materiilor prime în expresie valorică constă în exprimarea valorică a bugetului materiilor prime și se obține prin multiplicarea cifrelor din bugetul cantitativ cu costurile standard unitare ale fiecărui material consumat (nu cu prețuri curente și fără legătură cu valoarea de întrebuințare a produsului final)."},
{q:"Bugetul materialelor consumabile: a) se elaborează în expresie cantitativă, fizică; b) se elaborează în unități valorice; c) se întocmește pentru o firmă cu ciclu lung de fabricație caracterizată prin existența produselor în curs de fabricație.",o:["(b, c)","(a, b)","(a, b, c)","(a, c)"],a:2,m:"Corect: C (a, b, c). Bugetul materialelor consumabile se elaborează atât în expresie cantitativă (fizică), cât și în unități valorice, și se întocmește pentru firmele cu ciclu lung de fabricație, caracterizate prin existența produselor în curs de fabricație."},
{q:"Bugetul aprovizionării: a) evidențiază consumurile ocazionate de realizarea planului de fabricație; b) conține prețul de achiziție costul de aprovizionare (costul comenzii și costul transportului); c) conține costurile recepției, magazinajul și stocajul; d) conține costurile eventualelor stocuri de siguranță.",o:["(c, d)","(a, c)","(a, b, c, d)","(a, d)"],a:2,m:"Corect: C (a, b, c, d). Bugetul aprovizionării evidențiază consumurile ocazionate de realizarea planului de fabricație și conține: prețul de achiziție și costul de aprovizionare (comandă + transport), costurile recepției, magazinajul și stocajul, precum și costurile eventualelor stocuri de siguranță."},
{q:"La elaborarea bugetului comercial, trebuie să țină cont de următorii indicatori: a) nivelul cantităților de produse vândute pe diverse piețe; b) condițiile în care au loc vânzările; c) mărimea cheltuielilor directe ocazionate de vânzarea produselor; d) mărimea cheltuielilor indirecte ocazionate de vânzarea produselor.",o:["(a, b, c, d)","(a, b)","(a, b, c)","(a, d)"],a:0,m:"Corect: A (a, b, c, d). La elaborarea bugetului comercial se ține cont de: nivelul cantităților de produse vândute pe diverse piețe, condițiile în care au loc vânzările, mărimea cheltuielilor directe și mărimea cheltuielilor indirecte ocazionate de vânzarea produselor."},
{q:"La elaborarea bugetului comercial, trebuie să țină cont de următorii indicatori: a) mărimea cheltuielilor indirecte ocazionate de vânzarea produselor; b) mărimea veniturilor încasate din vânzări; c) nivelul marjelor comerciale standard; d) nivelul stocurilor de produse finite.",o:["(a, c, d)","(a, b)","(a, b, c, d)","(a, d)"],a:2,m:"Corect: C (a, b, c, d). Tot pentru bugetul comercial sunt relevanți: mărimea cheltuielilor indirecte de vânzare, mărimea veniturilor încasate din vânzări, nivelul marjelor comerciale standard și nivelul stocurilor de produse finite — toți cei patru indicatori."},
{q:"Responsabilitatea serviciului comercial constă în: a) gestionarea corectă a stocurilor materiale; b) realizarea unei analize judicioase a nivelului cheltuielilor ocazionate de stocarea produselor, comparativ cu cheltuielile de promovare, astfel încât pe ansamblu să se obțină un cost minim; c) întocmirea bugetului de materii prime; d) întocmirea bugetului comercial.",o:["(a, b, d)","(a, b)","(a, b, c, d)","(a, d)"],a:0,m:"Corect: A (a, b, d). Responsabilitatea serviciului comercial constă în gestionarea corectă a stocurilor materiale, analiza judicioasă a cheltuielilor de stocare comparativ cu cele de promovare/stimulare a vânzărilor (cost minim, profit maxim) și întocmirea bugetului comercial. Bugetul de materii prime (c) revine producției."},
{q:"Bugetul directorului (managerului) comercial: a) este întocmit de directorul (managerul) comercial; b) este întocmit de directorul (managerul) general; c) este întocmit pe baza planului firmei pe termen mediu, al bugetul producției (industrial), și al bugetului trezoreriei.",o:["(a, b)","(a, c)","(a, b, c)","(a)"],a:1,m:"Corect: B (a, c). Bugetul directorului comercial este întocmit de directorul (managerul) comercial, pe baza planului firmei pe termen mediu, a bugetului producției (industrial) și a bugetului trezoreriei — nu de directorul general."},
{q:"Bugetul directorului (managerului) comercial este întocmit pe baza: a) planului firmei pe termen mediu (cantități vândute, segmente de piață, imagine de marcă, politici de produs și distribuție); b) bugetului producției industrial (capacități de producție, gradul de utilizare, investiții); c) bugetului trezoreriei (capacitatea firmei de a-și finanța ciclul de producție și de a avea lichidități).",o:["(a, b, c)","(a, c)","(a, b)","(a)"],a:0,m:"Corect: A (a, b, c). Cele trei baze ale bugetului comercial: planul pe termen mediu (cantități vândute, segmente de piață, imagine de marcă, politici de produs și distribuție), bugetul producției (capacități, grad de utilizare, investiții) și bugetul trezoreriei (finanțarea ciclului de producție, lichidități)."},
{q:"Metoda de management Kanban a pornit de la constatarea că, în general, salariații firmei au tendința de a realiza:",o:["totdeauna supraproducție","produse de calitate","producție sub nivelul planificat","număr redus de rebuturi"],a:0,m:"Corect: A. Metoda Kanban a pornit de la constatarea lui M. Ohno (Toyota, 1958) că salariații firmei au tendința de a realiza totdeauna supraproducție — de aici nevoia unui sistem care să producă doar ce se cere, când se cere, cât se cere."},
{q:"Pentru a aplica metoda de management Kanban trebuie căutate și găsite acele mijloace, care să permită continuarea producției în următoarele condiții: a) producția să fie comandată (cerută); b) producția să se realizeze la termenul cerut de beneficiar; c) să se reducă cheltuielile fixe unitare; d) producția să fie fabricată în cantitatea solicitată; e) producția să fie realizată cu rebuturi minime.",o:["(a, b, d)","(a, b, c)","(a, b, c, d)","(c, e)"],a:0,m:"Corect: A (a, b, d). Condițiile continuării producției în metoda Kanban, conform cursului: producția să fie comandată (cerută), să se realizeze la termenul cerut de beneficiar și să fie fabricată în cantitatea solicitată. Reducerea cheltuielilor fixe și rebuturile minime nu fac parte din aceste condiții."},
{q:"Esența Metodei Kanban constă în:",o:["Un loc de muncă, un atelier etc. din aval, cere unui loc de muncă din amonte, să realizeze numai o anumită producție care lui îi este necesară și la rândul său el să realizeze acea producție, care îi este cerută de locul de muncă anterior, adică de cel din avalul său pentru care el ocupă poziția din amonte","Un loc de muncă, un atelier etc. din amonte, cere unui loc de muncă din aval, să realizeze numai o anumită producție care lui îi este necesară și la rândul său el să realizeze acea producție, care îi este cerută de locul de muncă următor, adică de cel din amontele său pentru care el ocupă poziția de aval, iar acesta din urmă să producă numai ceea ce este cerut de clienți","Un loc de muncă, un atelier etc. din aval, cere unui loc de muncă din amonte, să realizeze numai o anumită producție care lui îi este necesară și la rândul său el să realizeze acea producție, care îi este cerută de locul de muncă anterior, adică de cel din avalul său pentru care el ocupă poziția din amonte, iar acesta din urmă să producă numai ceea ce este cerut de clienți","Un loc de muncă, un atelier etc. din amonte, cere unui loc de muncă din aval, să realizeze producția maximă posibilă, care îi este cerută de locul de muncă următor, adică de cel din amontele său pentru care el ocupă poziția de aval, pentru a obține o valorificare superioară a resurselor"],a:1,m:"Corect: B. Suportul de curs formulează esența metodei exact așa: un loc de muncă din amonte cere unui loc de muncă din aval să realizeze numai producția care îi este necesară, fiecare realizând ceea ce îi este cerut de locul de muncă următor, iar ultimul produce numai ceea ce este cerut de clienți — cererile se transmit din aval spre amonte prin fluxul informațional Kanban."},
{q:"Metoda Kanban presupune analizarea și reprezentarea următoarelor fluxuri: a) flux tehnologic; b) flux financiar; c) flux informațional; d) flux monetar.",o:["(a, c)","(a, b, c)","(a, d)","(a, b, c, d)"],a:0,m:"Corect: A (a, c). Metoda Kanban presupune analizarea și reprezentarea a două fluxuri: fluxul tehnologic (circulația reperelor de la stânga la dreapta) și fluxul informațional în sens invers (etichetele Kanban, din aval spre amonte). Fluxurile financiar și monetar nu fac obiectul metodei."},
{q:"Aplicarea etichetelor de producție (Kanban) este posibilă dacă: a) locurile de muncă sunt consecutive pe fluxul tehnologic; b) se lucrează în mai multe schimburi; c) există spații de depozitare pentru containere la fiecare loc de muncă; d) tactul liniei este constant; e) există spații de depozitare pentru containere și între două locuri de muncă succesive.",o:["(a, b, e)","(a, b, c)","(c, e)","(a, c, e)"],a:3,m:"Corect: D (a, c, e). Aplicarea etichetelor de producție este posibilă dacă: locurile de muncă sunt consecutive pe fluxul tehnologic și există spații de depozitare pentru containere la fiecare loc de muncă și între două locuri de muncă succesive. Numărul de schimburi și constanța tactului nu condiționează aplicarea."},
{q:"Relația de determinare a numărului de containere și numărul de etichete (Kanban): numărul mediu de repere solicitat 420, cadența de fabricație 8 ore, capacitatea containerului 14 bucăți, coeficient de corecție 5%. Câte etichete rezultă?",o:["12 etichete","0,1875 → 1 etichetă","14700 etichete","5,33 → 6 etichete"],a:0,m:"Corect: A. Formula din curs: n = (N̄r × Rf × k)/Cc, unde k este coeficientul de corecție (sub 10% din N̄r × Rf). Înlocuind: n = (420 × 8 × 0,05)/14 = 168/14 = 12 etichete (containere)."},
{q:"La un loc de muncă, se fabrică trei tipuri de repere: R1 cu 6 etichete în circulație, R2 cu 5 etichete, R3 cu 2 etichete, iar în planul de producție există două etichete pentru fiecare reper. Variante corecte: a) pentru R1 vor fi în stocaj 4 containere; b) pentru R1 va fi în stocaj 1 container; c) pentru R2 vor fi în stocaj 3 containere; d) pentru R3 nu vor fi în stocaj containere; e) lansare preferențială R1; f) lansare preferențială R2; g) lansare preferențială R3.",o:["(a, b, c)","(a, c, d, g)","(a, b, c, f)","(a, c, f)"],a:1,m:"Corect: B (a, c, d, g). Containere în stocaj = etichete în circulație − etichete în planul de producție: R1: 6−2 = 4 containere; R2: 5−2 = 3 containere; R3: 2−2 = 0 containere. Deoarece R3 nu are containere în stocaj, este necesară lansarea sa preferențială în fabricație."},
{q:"Metoda O.P.T. (Technologie Production Optimisee): a) s-a aplicat în firme industriale pentru a elimina posibilele „intrări strangulate”; b) precizează că „strangulările” definesc în totalitate condițiile de producție din firmă; c) nu ține cont de „intrările strangulate”, ci de evidența stocurilor.",o:["(b, c)","(a, b)","(a, c)","(a)"],a:1,m:"Corect: B (a, b). Metoda O.P.T. s-a aplicat pentru a elimina „intrările strangulate” (resurse, mașini, utilaje, ateliere cu capacitate reală inferioară cererii pieței) și precizează că strangulările definesc în totalitate condițiile de producție, de care trebuie ținut cont pentru organizarea producției. Afirmația (c) inversează logica metodei."},
{q:"Metoda OPT folosește pe lângă „intrările ne-strangulate” și alți indicatori, care să releve performanțele firmei precum: a) valoarea vânzărilor; b) mărimea stocurilor; c) cheltuielile de exploatare.",o:["(c)","(a, b)","(a, b, c)","(a, c)"],a:2,m:"Corect: C (a, b, c). Pe lângă intrările ne-strangulate, metoda OPT folosește ca indicatori de performanță: valoarea vânzărilor, mărimea stocurilor și cheltuielile de exploatare — toți trei."},
{q:"Metoda O.P.T. este fundamentată pe un set de reguli. Dintre acestea fac parte: a) trebuie echilibrat fluxul tehnologic și nu capacitățile de producție; b) nivelul de utilizare a unor intrări strangulate nu se stabilește folosind propriul potențial, ci prin folosirea celorlalte restricții ale sistemului; c) utilizarea și folosirea deplină a unei resurse sunt noțiuni sinonime.",o:["(b, c)","(a, b)","(a, b, c)","(a, c)"],a:1,m:"Corect: B (a, b). Reguli OPT: trebuie echilibrat fluxul tehnologic, nu capacitățile de producție, iar nivelul de utilizare a intrărilor strangulate se stabilește prin celelalte restricții ale sistemului, nu prin propriul potențial. Afirmația (c) e falsă: utilizarea și folosirea deplină sunt noțiuni diferite, NU sinonime."},
{q:"Metoda O.P.T. este fundamentată pe un set de reguli. Dintre acestea fac parte: a) utilizarea și folosirea deplină a unei resurse sunt noțiuni diferite, deci nu sunt sinonime; b) oră pierdută în situația unei resurse insuficiente este de fapt o oră pierdută pentru întregul sistem de resurse; c) oră câștigată prin folosirea unei resurse ne-insuficiente nu prezintă importanță; d) resursele insuficiente determină atât nivelul intrărilor la fiecare loc de muncă, cât și nivelul stocurilor inițiale și intermediare.",o:["(c, d)","(a, b)","(a, d)","(a, b, c, d)"],a:3,m:"Corect: D (a, b, c, d). Toate cele patru sunt reguli OPT: utilizarea ≠ folosirea deplină a unei resurse; o oră pierdută la o resursă strangulată e pierdută pentru întregul sistem; o oră câștigată la o resursă ne-insuficientă nu prezintă importanță; resursele insuficiente determină nivelul intrărilor și al stocurilor inițiale și intermediare."},
{q:"Metoda SMED: a) presupune în principal fluidizarea traficului pieselor în firmă, prin evitarea transporturilor inutile; b) recomandă să se amplaseze locurile de muncă unul lângă altul și să se efectueze operații succesive prin minimizarea operațiilor de transport; c) presupune reducerea stocurilor intermediare din parcurs, simplificarea fluxului reperelor, creșterea vitezei de circulație în flux, și urmărirea facilă a fabricației.",o:["(a, c)","(a, b)","(a)","(a, b, c)"],a:3,m:"Corect: D (a, b, c). Metoda SMED presupune: fluidizarea traficului pieselor prin evitarea transporturilor inutile, amplasarea locurilor de muncă unul lângă altul cu operații succesive (minimizarea transportului și a costurilor) și reducerea stocurilor intermediare, simplificarea fluxului reperelor, creșterea vitezei de circulație și urmărirea facilă a fabricației."},
{q:"Metoda SMED: a) pune în linie operațiile, folosind drept mijloace de lucru celule de fabricație în ateliere; b) pune în linie fabricația diferitelor produse, descentralizarea activității de recepție, stocare și expediție; c) presupune facilitarea accesului la resursele deficitare.",o:["(a, c)","(a, b)","(a)","(b, c)"],a:1,m:"Corect: B (a, b). Metoda SMED pune în linie operațiile (folosind celule de fabricație în ateliere) și pune în linie fabricația diferitelor produse, cu descentralizarea activității de recepție, stocare și expediție. Facilitarea accesului la resurse deficitare (c) ține de OPT, nu de SMED."},
{q:"La aplicarea Metodei SMED atelierele în flux (Flow shop) sunt cele: a) în care fluxul pieselor este evident — materiile prime intră pe de o parte și produsele finite ies pe de altă parte, mașinile fiind în general specializate; b) de mecanică generală, în care trebuie apelat la tehnologia de grupare a pieselor pentru a se transforma în atelier în flux; c) constituite din un set de mașini capabile să realizeze un ansamblu de piese trecând rapid de la fabricarea uneia la alta, cu un flux principal care permite amplasarea optimă a mașinilor.",o:["(b, c)","(a, b)","(a, b, c)","(a)"],a:3,m:"Corect: D (a). Atelierele în flux (Flow shop) sunt cele în care fluxul pieselor este evident — materiile prime intră pe de o parte, produsele finite ies pe de altă parte, iar mașinile sunt în general specializate (producție de serie mare, industrie chimică, alimentară). (b) descrie Job shop, (c) descrie celulele flexibile."},
{q:"Implementarea metodei SMED presupune parcurgerea mai multor etape. Dintre acestea fac parte: a) stabilirea distinctă a operațiilor IED și OED; b) transformarea operațiilor IED în OED; c) aplicarea unor standarde de funcțiuni; d) adoptarea unor restrângeri funcționale; e) adoptarea unor măsuri pentru sincronizarea lucrului; f) suprimarea reglajelor; g) folosirea mecanizării.",o:["(a, b, c, d, e, f, g)","(a, b, c)","(a, c, e)","(e, f)"],a:0,m:"Corect: A (toate). Implementarea SMED parcurge toate etapele enumerate: stabilirea distinctă a operațiilor IED și OED, transformarea IED în OED, aplicarea standardelor de funcțiuni, adoptarea restrângerilor funcționale, măsuri pentru sincronizarea lucrului, suprimarea reglajelor și folosirea mecanizării."},
{q:"Metoda MRP 1:",o:["este folosită pentru planificarea necesarului, pornindu-se de la elementele componente ale nomenclatorului de fabricație","servește pentru planificarea necesarului, având drept punct de plecare elementele componente realizate în buclă închisă pe baza noțiunii de prioritate","apreciază gestiunea de ansamblu a Planului Industrial și Comercial sau a gestiunii de urmărire a producției","este recomandabilă pentru o gestiune pe termen scurt, integrând conceptele de tip just (real) stabilite de firmele japoneze"],a:1,m:"Corect: B. Metoda MRP 1 servește pentru planificarea necesarului, având drept punct de plecare elementele componente, realizată în buclă închisă pe baza noțiunii de prioritate. Varianta A descrie MRP 0 (punctul de plecare: nomenclatorul de fabricație), C descrie MRP 2, D descrie MRP just-in-time."},
{q:"Metoda MRP: a) distinge necesarul independent, care constituie granița între firme și mediul său exterior (produse finite, piese de schimb etc.); b) distinge necesarul dependent, determinat de necesarul independent și calculat pornind de la descompunerea produselor finite în elementele componente; c) se aplică cu succes în firmele industriale care produc produse finite simple; d) se aplică cu succes în situația firmelor industriale care produc produse finite complexe formate din foarte multe elemente componente.",o:["(a, b, d)","(a, b, c)","(a, c)","(b, c)"],a:0,m:"Corect: A (a, b, d). Metoda MRP distinge necesarul independent (granița firmă–mediu exterior: produse finite, piese de schimb) și necesarul dependent (calculat prin descompunerea produselor finite în componente) și se aplică cu succes în firmele care produc produse finite complexe, formate din foarte multe elemente componente — nu simple."},
{q:"Metoda MRP 2: a) se poate aplica cu succes pentru economia României; b) permite glisarea producției de pe termen lung pe termen scurt; c) este o metodă de simulare a activității industriale.",o:["(a, b)","(a, c)","(a, b, c)","(b, c)"],a:2,m:"Corect: C (a, b, c). Conform cursului, MRP 2 se poate aplica cu succes pentru economia României, permite glisarea producției de pe termen lung pe termen scurt și este în egală măsură o metodă de simulare a activității industriale."},
{q:"La aplicarea Metodei SMED distingem următoarele tipuri de ateliere: a) ateliere în flux (Flow shop); b) ateliere pe operații (Job shop); c) ateliere–celule flexibile de fabricație.",o:["(a, c)","(a, b)","(a)","(a, b, c)"],a:3,m:"Corect: D (a, b, c). La aplicarea metodei SMED se disting trei tipuri de ateliere: ateliere în flux (Flow shop), ateliere pe operații (Job shop) și ateliere-celule flexibile de fabricație."},
{q:"La Metoda MRP 2, calculele de încărcare globală: a) permit să se verifice în general dacă necesarul planificat este în concordanță cu capacitatea firmei; b) arată dacă există pericolul iminent sau mai îndepărtat ca prevederile din Planul industrial și comercial și cele din Programul director de producție să nu poată fi realizate de firmă; c) permit a se stabili ansamblul ordinii de fabricație.",o:["(a, b)","(a, b, c)","(a, c)","(b, c)"],a:0,m:"Corect: A (a, b). La MRP 2, calculele de încărcare globală permit verificarea concordanței necesarului planificat cu capacitatea firmei și arată dacă există pericolul (iminent sau îndepărtat) ca prevederile din Planul industrial și comercial și din Programul director de producție să nu poată fi realizate. Ordinea de fabricație (c) se stabilește prin alte calcule."}
  ]
},

managementStrategic: {
  label: "Management strategic",
  color: "#5C2E5C",
  questions: [
{q:"Setul de decizii si acțiuni manageriale care determină performanța pe termen lung a unei firme definește:",o:["managementul strategic","strategia","planul strategic","sistemul strategic"],a:0,m:"Corect: A. Managementul strategic este definit în curs (cap. 1) ca setul de decizii și acțiuni manageriale care determină performanța pe termen lung a unei firme. Strategia și planul strategic sunt componente/rezultate ale acestui proces, nu procesul însuși."},
{q:"Modelul fundamental al managementului strategic reunește: a) strategiile corporatiste; b) implementarea strategiei; c) scanarea mediului; d) formularea strategiei; e) strategiile de afaceri; f) strategiile funcționale; g) evaluare și control.",o:["(a, b, c, d, e, f, g)","(a, e, f)","(b, c, d, g)","(c, d, g)"],a:2,m:"Corect: C. Modelul fundamental al managementului strategic (cap. 1) reunește patru elemente: scanarea mediului, formularea strategiei, implementarea strategiei și evaluare & control → (b, c, d, g). Strategiile corporatiste, de afaceri și funcționale sunt niveluri ale strategiei, nu etape ale modelului."},
{q:"Formularea strategiei reunește: a) definirea misiunii organizației; b) stabilirea obiectivelor de atins; c) dezvoltarea strategiilor; d) stabilirea politicilor specifice.",o:["(a, b, c)","(a, b)","(c, d)","(a, b, c, d)"],a:3,m:"Corect: D. Formularea strategiei (cap. 1) cuprinde: definirea misiunii organizației, stabilirea obiectivelor de atins, dezvoltarea strategiilor și stabilirea politicilor specifice → toate cele patru (a, b, c, d)."},
{q:"Printre caracteristicile deciziei strategice nu se numără faptul că aceasta este:",o:["directivă","uzuală/comună","rară","importantă/majoră"],a:1,m:"Corect: B. Decizia strategică (cap. 1) are trei caracteristici: este rară (neobișnuită, fără precedent), importantă/majoră (angajează resurse semnificative) și directivă (stabilește precedente pentru deciziile viitoare). „Uzuală/comună” contrazice caracterul rar — deci B nu se numără printre caracteristici."},
{q:"Analiza PEST are în vedere:",o:["mediul natural","mediul societal","mediul sarcină","mediul intern"],a:1,m:"Corect: B. Analiza PEST (politic, economic, socio-cultural, tehnologic) vizează mediul societal — forțele generale care nu ating direct activitățile pe termen scurt, dar influențează deciziile pe termen lung (cap. 3). Mediul sarcină cuprinde grupurile care afectează direct firma."},
{q:"Factorii strategici externi ai unei firme sunt acele tendințe cheie ale mediului considerate a avea:",o:["o probabilitate de apariție redusă-medie si o probabilitate de impact asupra organizației medie-ridicată","o probabilitate de apariție medie-ridicată si o probabilitate de impact asupra organizației redusă-medie","o probabilitate de apariție medie-ridicată sau o probabilitate de impact asupra organizației medie-ridicată","o probabilitate de apariție medie-ridicată și o probabilitate de impact asupra organizației medie-ridicată"],a:3,m:"Corect: D. Factorii strategici externi (cap. 3) sunt tendințele cheie ale mediului considerate a avea atât o probabilitate de apariție medie-ridicată, ȘI o probabilitate de impact asupra organizației medie-ridicată — ambele condiții cumulate (conjuncție, nu disjuncție)."},
{q:"Potrivit lui Porter, sursele majore pentru barierele de intrare (într-o industrie) sunt reprezentate de: a) nevoile de fonduri; b) costurile de reorientare; c) puterea de negociere a clienților/consumatorilor; d) puterea de negociere a furnizorilor; e) economiile de scară; f) diferențierea produsului; g) politica guvernului; h) concurența dintre firmele existente; i) accesul la canalele de distribuție; j) dezavantaje de cost fără legătură cu economiile de scară.",o:["(a, c, d, e, f, i, j)","(b, c, d, g, h, i)","(a, b, e, f, g, i, j)","(b, d, e, f, h)"],a:2,m:"Corect: C. Sursele majore ale barierelor de intrare la Porter (cap. 3): economiile de scară, diferențierea produsului, nevoile de fonduri, costurile de reorientare, accesul la canalele de distribuție, dezavantajele de cost independente de scară și politica guvernului → (a, b, e, f, g, i, j). Puterea de negociere a clienților/furnizorilor și rivalitatea sunt forțe distincte în modelul celor 5 forțe, nu bariere de intrare."},
{q:"Furnizorii sunt mai influenți în următoarele situații: a) există puțini furnizori; b) există substituenți disponibili pentru produsul oferit; c) produsul/serviciul oferit presupune costuri ridicate de transfer; d) produsul/serviciul oferit e nediferențiat; e) furnizorul își poate, în principiu, însuși procesul de adăugare a valorii al organizației; f) prețurile furnizorilor formează o parte considerabilă a cheltuielilor totale de exploatare ale organizației.",o:["(a, c, e, f)","(b, d, e, f)","(b, c, d, e)","(a, d, e, f)"],a:0,m:"Corect: A. Furnizorii sunt mai influenți când (cap. 3): sunt puțini, produsul presupune costuri ridicate de transfer, furnizorul se poate integra în aval (își poate însuși procesul de adăugare a valorii) și prețurile sale au pondere mare în cheltuielile de exploatare → (a, c, e, f). Existența substituenților (b) și produsul nediferențiat (d) REDUC puterea furnizorilor."},
{q:"Următoarea afirmație privind capabilitățile unei firme e falsă:",o:["capabilitățile au în vedere abilitatea unei firme de a-și exploata resursele","capabilitățile sunt procese și rutine de afaceri care gestionează interacțiunea dintre resurse pentru a transforma input-urile în output-uri","capabilitățile au un fundament funcțional","capabilitățile privesc integrarea și coordonarea inter-funcțională a competențelor firmei"],a:3,m:"Corect: D (afirmația falsă). Capabilitățile au fundament funcțional și privesc abilitatea firmei de a-și exploata resursele prin procese și rutine de afaceri (A–C adevărate). Integrarea și coordonarea inter-funcțională definesc COMPETENȚELE (competențele de bază), nu capabilitățile (cap. 4)."},
{q:"Cadrul analitic VRIO vizează analiza și evaluarea:",o:["resurselor și competențelor unei firme","oportunităților și amenințărilor mediului extern","performanțelor organizaționale","factorilor strategici ai industriei"],a:0,m:"Corect: A. Cadrul analitic VRIO (Valoare, Raritate, Imitabilitate, Organizare) vizează analiza și evaluarea resurselor și competențelor unei firme — instrument al abordării bazate pe resurse din scanarea mediului intern (cap. 4)."},
{q:"Analiza lanțului valorii firmei are în vedere următoarele activități de susținere/suport: a) infrastructura firmei; b) serviciile; c) marketingul și vânzările; d) aprovizionarea; e) dezvoltarea tehnologiei (C&D); f) managementul resurselor umane; g) logistica operațiunilor interne; h) exploatarea/producția/operațiile; i) logistica operațiunilor externe.",o:["(a, b, c, d)","(a, d, e, f)","(b, c, h, i)","(f, g, h, i)"],a:1,m:"Corect: B. În lanțul valorii (Porter, cap. 4), activitățile de susținere/suport sunt: infrastructura firmei, aprovizionarea, dezvoltarea tehnologiei (C&D) și managementul resurselor umane → (a, d, e, f). Logistica internă/externă, operațiile, marketingul și serviciile sunt activități primare."},
{q:"Pentru o firmă de mărime medie, cu câteva linii de produse, și care operează într-o singură industrie, este potrivit următorul tip de structură organizatorică:",o:["simplă","divizională","funcțională","matricială"],a:2,m:"Corect: C. Pentru o firmă de mărime medie, cu câteva linii de produse într-o singură industrie, este potrivită structura funcțională (cap. 4/8). Structura simplă e pentru firme mici antreprenoriale, cea divizională pentru firme mari cu multe linii de produse în mai multe industrii."},
{q:"Diviziile (grupurile de divizii) definite de segmente independente de tipul produs-piață, cărora li se acordă responsabilitate și autoritate în privința managementului propriilor arii funcționale, poartă denumirea de:",o:["conglomerate","unități de afaceri strategice","grupuri strategice","centre de cost"],a:1,m:"Corect: B. Diviziile definite de segmente independente produs-piață, cu responsabilitate și autoritate asupra propriilor arii funcționale, se numesc unități de afaceri strategice (Strategic Business Units — SBU) (cap. 4/8). Conglomeratele sunt ansambluri de firme fără legătură."},
{q:"Ansamblul de credințe, așteptări și valori învățate și împărtășite de membrii unei firme și transmise de la o generație de angajați la alta, definește:",o:["misiunea firmei","climatul organizațional","cultura organizațională","istoria firmei"],a:2,m:"Corect: C. Cultura organizațională = ansamblul de credințe, așteptări și valori învățate și împărtășite de membrii firmei și transmise de la o generație de angajați la alta — definiția din cap. 4."},
{q:"Cercetarea ce are în vedere îmbunătățirea controlului calității, a specificațiilor tehnice și a echipamentului de producție, care conduce la reducerea costurilor de producție și a defectelor și la creșterea eficienței – este:",o:["C&D de produs","C&D de marketing","C&D fundamentală","C&D de proces"],a:3,m:"Corect: D. Cercetarea care vizează îmbunătățirea controlului calității, a specificațiilor tehnice și a echipamentului de producție — cu reducerea costurilor și defectelor și creșterea eficienței — este C&D de proces (cap. 4/7). C&D de produs vizează produse noi, cea fundamentală — cunoașterea de bază."},
{q:"Managementul lanțului de aprovizionare (Supply Chain Management) are în vedere formarea de rețele pentru: a) aprovizionarea cu materii prime; b) realizarea de produse sau servicii; c) depozitarea și distribuția bunurilor; d) livrarea bunurilor către clienți/consumatori.",o:["(a, b, c, d)","(a)","(a, d)","(b, c)"],a:0,m:"Corect: A. Managementul lanțului de aprovizionare (SCM) are în vedere formarea de rețele pentru toate cele patru: aprovizionarea cu materii prime, realizarea de produse/servicii, depozitarea și distribuția bunurilor și livrarea către clienți/consumatori (a, b, c, d)."},
{q:"Procesul de găsire a unei „potriviri” strategice între Oportunități (O) si Puncte forte (S), în timp ce se evită impactul Punctelor slabe (W) si al Amenințărilor (T) – definește:",o:["analiza situațională","analiza de sistem","analiza nevoilor","analiza pieței"],a:0,m:"Corect: A. Analiza situațională (SWOT/SFAS, cap. 5) = procesul de găsire a unei potriviri strategice între oportunitățile externe (O) și punctele forte interne (S), evitând simultan impactul punctelor slabe (W) și al amenințărilor (T)."},
{q:"Strategia care urmărește îmbunătățirea poziției competitive a produselor/serviciilor unei companii/unități de afaceri în cadrul industriei sau segmentului de piață specific servit – este:",o:["strategia corporatistă","strategia funcțională","strategia de afaceri","strategia generică"],a:2,m:"Corect: C. Strategia de afaceri (business strategy, cap. 5) urmărește îmbunătățirea poziției competitive a produselor/serviciilor unei companii/unități de afaceri în cadrul industriei sau segmentului de piață servit. Strategia corporatistă privește ansamblul firmei, cea funcțională — maximizarea productivității resurselor."},
{q:"Strategia de afaceri poate fi:",o:["ofensivă și/sau defensivă","competitivă și/sau de cooperare","de marketing și/sau de resurse umane","de consolidare și/sau dezvoltare"],a:1,m:"Corect: B. Strategia de afaceri poate fi competitivă (lupta cu toți concurenții pentru avantaj) și/sau de cooperare (lucrul cu una sau mai multe firme împotriva altora) — cele două fațete definite în cap. 5."},
{q:"Încercuirea și manevra de flancare sunt: a) tactici ofensive; b) tactici defensive; c) tactici referitoare la locul pe piață în care o firmă își implementează strategia; d) tactici referitoare la timp; e) strategii ofensive; f) strategii defensive.",o:["(c, e)","(d, f)","(a, d)","(a, c)"],a:3,m:"Corect: D. Încercuirea și manevra de flancare sunt tactici ofensive și, ca localizare, tactici referitoare la locul pe piață în care firma își implementează strategia (se atacă pozițiile concurentului) → (a, c). Tacticile sunt sub-nivelul operațional al strategiilor, nu strategii propriu-zise (cap. 5)."},
{q:"În categoria tacticilor defensive se încadrează: a) ridicarea de bariere structurale; b) creșterea retorsiunii așteptate; c) atacul de gherilă; d) tactica primului intrat; e) reducerea tentației atacului; f) asaltul frontal.",o:["(c, d, f)","(c, e, f)","(a, b, e)","(b, c, e)"],a:2,m:"Corect: C. Tacticile defensive (cap. 5): ridicarea de bariere structurale, creșterea retorsiunii așteptate și reducerea tentației atacului → (a, b, e). Atacul de gherilă, asaltul frontal și tactica primului intrat sunt tactici ofensive/de timp."},
{q:"Motivațiile alianțelor strategice au în vedere: a) reducerea riscului financiar și/sau politic; b) accesul la capabilități tehnologice sau de producție; c) obținerea avantajului competitiv; d) accesul la anumite piețe.",o:["(a, b)","(c)","(c, d)","(a, b, c, d)"],a:3,m:"Corect: D. Motivațiile alianțelor strategice (cap. 5) includ toate cele patru: reducerea riscului financiar și/sau politic, accesul la capabilități tehnologice sau de producție, obținerea avantajului competitiv și accesul la anumite piețe (a, b, c, d)."},
{q:"Formele de alianță puternică și strânsă, în care o companie/unitate de afaceri formează un aranjament pe termen lung cu un furnizor cheie sau un distribuitor pentru avantajul reciproc poartă denumirea de:",o:["consorțiu de servicii reciproce","parteneriat pe lanțul valorii","societate mixtă","acord de licențiere/francizare"],a:1,m:"Corect: B. Parteneriatul pe lanțul valorii = forma de alianță puternică și strânsă în care o companie/unitate de afaceri formează un aranjament pe termen lung cu un furnizor cheie sau un distribuitor, pentru avantaj reciproc (cap. 5). Consorțiul de servicii reciproce e o alianță slabă între firme similare."},
{q:"Strategia corporatistă reunește următoarele aspecte cheie: a) strategia direcțională; b) strategia competitivă; c) strategia de afaceri; d) strategia funcțională; e) analiza portofoliului; f) parentingul corporatist.",o:["(a, e, f)","(b, c, d)","(b, e, f)","(c, d, e)"],a:0,m:"Corect: A. Strategia corporatistă (cap. 6) reunește trei aspecte cheie: strategia direcțională (orientarea spre creștere/stabilitate/restrângere), analiza portofoliului (industriile/piețele în care concurează) și parentingul corporatist (coordonarea activităților și transferul de resurse între linii) → (a, e, f)."},
{q:"Strategia direcțională a unei corporații poate avea în vedere următoarele orientări generale: a) redresare; b) creștere; c) concentrare; d) restrângere; e) diversificare; f) stabilitate; g) recoltare.",o:["(c, d, g)","(a, e, g)","(b, d, f)","(b, d, g)"],a:2,m:"Corect: C. Orientările generale ale strategiei direcționale (cap. 6): creștere, stabilitate și restrângere → (b, d, f). Redresarea, recoltarea, dezinvestiția sunt strategii specifice în interiorul restrângerii; concentrarea și diversificarea sunt strategii de creștere."},
{q:"Strategia prin care o firmă își asumă o funcție asigurată anterior de către un furnizor este de tip:",o:["diversificare concentrică","integrare în amonte","integrare în aval","diversificare conglomerat"],a:1,m:"Corect: B. Preluarea de către firmă a unei funcții asigurate anterior de un furnizor = integrare în amonte (backward integration) — creștere verticală în sens invers lanțului (cap. 6). Integrarea în aval preia funcții ale distribuitorilor."},
{q:"Măsura în care o firmă operează în mai multe locații geografice aflate la același nivel pe lanțul valorii industriei definește:",o:["integrarea orizontală","integrarea verticală","diversificarea","creșterea"],a:0,m:"Corect: A. Integrarea orizontală = măsura în care o firmă operează în mai multe locații geografice aflate la același nivel pe lanțul valorii industriei (cap. 6). Integrarea verticală presupune niveluri diferite ale lanțului (furnizor → distribuitor)."},
{q:"Strategia potrivită atunci când managementul firmei realizează faptul că industria actuală este neatractivă, iar firmei îi lipsesc abilități sau competențe extraordinare pe care să le poată transfera ușor unor produse/servicii în industrii înrudite - este:",o:["diversificarea concentrică","externalizarea","extinderea pieței","diversificarea (de tip) conglomerat"],a:3,m:"Corect: D. Diversificarea conglomerat (cap. 6) este potrivită când managementul constată că industria actuală este neatractivă, iar firmei îi lipsesc abilități/competențe extraordinare transferabile către produse/servicii din industrii înrudite → se diversifică în industrii FĂRĂ legătură. Diversificarea concentrică ar cere tocmai competențe transferabile."},
{q:"Din categoria strategiilor de stabilitate fac parte următoarele: a) dezinvestiția; b) recoltare/„nicio schimbare”; c) „pauză/continuare cu precauție”; d) stabilizarea profiturilor; e) firmă captivă; f) dezvoltarea de la zero.",o:["(a, e, f)","(a, d, f)","(b, c, d)","(b, c, e)"],a:2,m:"Corect: C. Strategiile de stabilitate (cap. 6): „pauză/continuare cu precauție”, „nicio schimbare” (recoltare/no change) și stabilizarea profiturilor → (b, c, d). Dezinvestiția, firma captivă și dezvoltarea de la zero aparțin altor orientări (restrângere/creștere)."},
{q:"Opțiunea vânzării unei unități de afaceri poartă denumirea de:",o:["dezinvestiție","consolidare","lichidare","faliment"],a:0,m:"Corect: A. Vânzarea unei unități de afaceri se numește dezinvestiție (divestment) — strategie de restrângere (cap. 6). Lichidarea presupune încetarea și vânzarea activelor firmei întregi, consolidarea e o etapă a redresării."},
{q:"Matricea portofoliului BCG combină, pentru fiecare din liniile de produse/unitățile de afaceri: a) competențele cheie ale firmei; b) capabilitățile organizaționale distinctive; c) indicele de creștere a industriei; d) cota relativă de piață.",o:["(a, b)","(c, d)","(b, c)","(a, d)"],a:1,m:"Corect: B. Matricea portofoliului BCG (cap. 6) combină, pentru fiecare linie de produse/unitate de afaceri, indicele (rata) de creștere a industriei și cota relativă de piață → (c, d). Competențele și capabilitățile țin de analiza internă, nu de matricea BCG."},
{q:"Prin apelarea la o strategie de dezvoltare a pieței, o firmă/unitate de afaceri poate: a) câștiga o cotă mai mare pe o piață existentă pentru produsele sale actuale; b) dezvolta noi utilizări și/sau piețe pentru produsele sale actuale; c) dezvolta noi produse pentru piețele existente; d) dezvolta noi produse pentru piețe noi.",o:["(b, c)","(c, d)","(b, d)","(a, b)"],a:3,m:"Corect: D. Prin strategia de dezvoltare a pieței (cap. 6), firma poate câștiga o cotă mai mare pe o piață existentă pentru produsele actuale (penetrare prin dezvoltarea pieței) și poate dezvolta noi utilizări și/sau piețe pentru produsele actuale → (a, b). Produse noi ar însemna dezvoltarea produsului sau diversificare."},
{q:"Obținerea de economii prin combinarea activităților necesare fabricației diferitelor produse – caracterizează:",o:["economiile de scară","strategia de lider prin cost","economiile de rețea","economiile de scop"],a:3,m:"Corect: D. Economiile de scop (economies of scope, cap. 6) = obținerea de economii prin combinarea activităților necesare fabricației diferitelor produse (resurse partajate între linii). Economiile de scară provin din volumul unui singur produs."},
{q:"O companie/unitate de afaceri ar trebui să apeleze la externalizarea unei activități doar în cazul în care:",o:["ponderea acesteia în valoarea adăugată totală (a companiei/unității de afaceri) este redusă, și avantajul competitiv al activității respective este scăzut","ponderea acesteia în valoarea adăugată totală (a companiei/unității de afaceri) este ridicată, și avantajul competitiv al activității respective este scăzut","ponderea acesteia în valoarea adăugată totală (a companiei/unității de afaceri) este redusă, și avantajul competitiv al activității respective este ridicat","ponderea acesteia în valoarea adăugată totală (a companiei/unității de afaceri) este ridicată, și avantajul competitiv al activității respective este ridicat"],a:0,m:"Corect: A. Matricea externalizării (cap. 7): o activitate ar trebui externalizată doar când ponderea ei în valoarea adăugată totală este redusă ȘI avantajul competitiv al activității respective este scăzut. Activitățile cu avantaj competitiv ridicat se păstrează intern."},
{q:"Bilanțurile și conturile de profit & pierdere pro forma (estimative) care prognozează efectul pe care fiecare alternativă strategică e probabil să-l aibă asupra rentabilității investițiilor (ROI) diviziei și corporației – dau conținutul:",o:["indicatorilor financiari","evaluării performanțelor","scenariilor corporative","strategiei financiare"],a:2,m:"Corect: C. Scenariile corporative (cap. 7) = bilanțurile și conturile de profit & pierdere pro forma care prognozează efectul fiecărei alternative strategice (și al programelor aferente) asupra rentabilității investițiilor (ROI) la nivel de divizie și corporație — instrument al alegerii strategice."},
{q:"Sistemele secvențiale ale etapelor sau tehnicilor care descriu în detaliu modul în care trebuie efectuată o anumită sarcină sau activitate poartă denumirea de:",o:["programe","proceduri","bugete","politici"],a:1,m:"Corect: B. Procedurile (Standard Operating Procedures, cap. 8) = sistemele secvențiale ale etapelor sau tehnicilor care descriu în detaliu modul de efectuare a unei sarcini sau activități. Programele sunt activități cu scop unic, bugetele — expresia financiară a programelor, politicile — linii directoare largi."},
{q:"Reengineering-ul (reproiectarea organizațională) este:",o:["o strategie","un tip de structură organizatorică","un plan","un program"],a:3,m:"Corect: D. Reengineering-ul (reproiectarea organizațională, cap. 8) este un program de implementare a strategiei — regândirea radicală a proceselor de afaceri, fără a fi o strategie, o structură sau un plan în sine."},
{q:"Corporația care urmează o strategie de concentrare ce urmărește creșterea verticală sau orizontală și-ar dori probabil un (nou) manager agresiv, cu o mare experiență în industria respectivă – de tipul:",o:["expert al dinamicii industriei","manager de portofoliu analitic","planificator prudent","specialist în redresare"],a:0,m:"Corect: A. O corporație cu strategie de concentrare (creștere verticală sau orizontală) are nevoie de un manager agresiv, cu mare experiență în industria respectivă — tipul „expert al dinamicii industriei” (cap. 8, corelarea managerului cu strategia). Managerul de portofoliu se potrivește diversificării, specialistul în redresare — declinului."},
{q:"Abordarea integratoare la nivel organizațional, care contribuie la asigurarea direcționării acțiunilor către obiectivele urmărite prin corelarea obiectivelor organizaționale cu comportamentul individual – poartă denumirea de:",o:["strategie corporativă","management prin obiective","planificarea strategică","implementare a strategiei"],a:1,m:"Corect: B. Managementul prin obiective (MBO, cap. 8) = abordarea integratoare la nivel organizațional care asigură direcționarea acțiunilor către obiectivele urmărite prin corelarea obiectivelor organizaționale cu comportamentul individual (stabilire participativă de obiective în cascadă)."},
{q:"Cotele de vânzări, obiectivele specifice privind reducerea costurilor sau creșterea profiturilor, studiile privind satisfacția clienților sunt forme ale controlului:",o:["intrărilor","conduitei","ieșirilor","resurselor"],a:2,m:"Corect: C. Cotele de vânzări, obiectivele de reducere a costurilor/creștere a profiturilor și studiile de satisfacție a clienților sunt forme ale controlului ieșirilor (output controls) — specifică REZULTATELE de atins, nu comportamentele sau resursele (cap. 9)."},
{q:"Potrivit tabloului de bord (balanced scorecard), domeniile în care managementul trebuie să dezvolte scopuri sau obiective sunt: a) financiar; b) organizare; c) perspectiva internă asupra afacerilor; d) clienți; e) motivare; f) inovare și învățare.",o:["(b, c, e, f)","(a, b, d, e)","(c, d, e, f)","(a, c, d, f)"],a:3,m:"Corect: D. Domeniile balanced scorecard (Kaplan & Norton, cap. 9): financiar, clienți, perspectiva internă asupra afacerilor și inovare & învățare → (a, c, d, f). Organizarea și motivarea nu sunt perspective ale tabloului de bord."},
{q:"Procesul continuu de comparare a produselor, serviciilor și practicilor unei firme cu cele ale celor mai puternici concurenți sau cu cele ale companiilor recunoscute ca fiind lideri ai industriei, în vederea îmbunătățirii propriilor tehnici – poartă denumirea de:",o:["benchmarking","evaluare și control","măsurare a performanțelor","aplicare a acțiunilor corective"],a:0,m:"Corect: A. Benchmarking-ul (cap. 9) = procesul continuu de comparare a produselor, serviciilor și practicilor firmei cu cele ale celor mai puternici concurenți sau ale liderilor recunoscuți ai industriei, în vederea îmbunătățirii propriilor tehnici."},
{q:"Principalii indicatori de măsurare a performanței corporative au în vedere: a) randamentul investiției; b) ponderea vânzărilor de produse noi; c) vânzările pe angajat; d) câștigul pe acțiune; e) costurile unitare; f) rentabilitatea capitalului propriu; g) fluxul de numerar din activitatea curentă; h) satisfacția în muncă.",o:["(b, c, e, h)","(a, b, c, d)","(a, d, f, g)","(b, d, f, g)"],a:2,m:"Corect: C. Principalii indicatori de măsurare a performanței corporative (cap. 9): randamentul investiției (ROI), câștigul pe acțiune (EPS), rentabilitatea capitalului propriu (ROE) și fluxul de numerar din activitatea curentă (cash-flow operațional) → (a, d, f, g)."},
{q:"În cadrul procesului de control strategic, cantitatea minimă de informații necesare pentru a oferi o imagine relevantă asupra evenimentelor:",o:["nu se poate estima","e reprezentată de totalitatea activităților derulate și a rezultatelor obținute","se poate estima prin intermediul regulii celor mai mici pătrate","se poate estima prin intermediul regulii 80/20"],a:3,m:"Corect: D. În controlul strategic (cap. 9), cantitatea minimă de informații necesare pentru o imagine relevantă asupra evenimentelor se poate estima prin regula 80/20 (Pareto): 20% dintre factori explică 80% din rezultate — se monitorizează cei 20%."},
{q:"În cazul unei corporații organizată divizional, dacă ROI-ul fiecărei divizii este superior celui care ar fi obținut în cazul în care fiecare divizie ar exista/funcționa ca afacere distinctă – se spune că există:",o:["performanță","sinergie","avantaj competitiv","profitabilitate"],a:1,m:"Corect: B. Sinergia (cap. 9) există într-o corporație divizională atunci când ROI-ul fiecărei divizii este superior celui pe care l-ar obține diviziile funcționând ca afaceri distincte — întregul valorează mai mult decât suma părților (2+2=5)."},
{q:"Abordarea relativ nouă a cercetării-dezvoltării, potrivit căreia o firmă apelează la alianțe și conexiuni cu alte firme, instituții publice, laboratoare academice, consumatori pentru a dezvolta noi produse și procese poartă numele de:",o:["inovație deschisă","inovație disruptivă","inovație de produs","inovație de proces"],a:0,m:"Corect: A. Inovația deschisă (open innovation, cap. 7 — strategia funcțională de C&D) = abordarea prin care firma apelează la alianțe și conexiuni cu alte firme, instituții publice, laboratoare academice și consumatori pentru a dezvolta noi produse și procese."},
{q:"Preocuparea majoră a strategiei funcționale este:",o:["stabilitatea, creșterea sau redresarea","diferențierea sau leadership-ul prin costuri","maximizarea productivității resurselor","direcția generală a firmei"],a:2,m:"Corect: C. Preocuparea majoră a strategiei funcționale (cap. 7) este maximizarea productivității resurselor — dezvoltarea și cultivarea competențelor distinctive în cadrul fiecărei funcțiuni. Direcția generală e treaba strategiei corporatiste, poziția competitivă — a celei de afaceri."},
{q:"Următoarea afirmație este adevărată:",o:["pentru a fi eficace, managementul strategic trebuie sa îmbrace întotdeauna forma unui proces formalizat","flexibilitatea strategică cere din partea firmelor să devină organizații care învață","pentru a fi competitive in medii dinamice, firmele trebuie sa devină mai birocratice și mai flexibile","realizarea scopurilor ar trebui sa conducă la îndeplinirea misiunii organizației"],a:1,m:"Corect: B. Afirmația adevărată: flexibilitatea strategică cere din partea firmelor să devină organizații care învață (learning organizations, cap. 1). A e falsă (managementul strategic nu trebuie să fie întotdeauna proces formalizat), C e contradictorie (birocratic ≠ flexibil), D confundă termenii — în terminologia cursului, realizarea OBIECTIVELOR (cuantificate) conduce la îndeplinirea misiunii, scopurile fiind enunțuri deschise, necuantificate."},
{q:"Tendința populației spre o alimentație mai sănătoasă poate reprezenta pentru o firmă:",o:["un punct slab sau un punct forte","o competență cheie","o capabilitate dinamică","o oportunitate sau o amenințare"],a:3,m:"Corect: D. Tendința populației spre o alimentație mai sănătoasă este un factor al mediului EXTERN, deci poate reprezenta pentru firmă o oportunitate sau o amenințare (cap. 3). Punctele forte/slabe, competențele și capabilitățile sunt variabile interne."},
{q:"Care dintre următoarele afirmații este un exemplu de misiune a firmei?",o:["diversificarea liniei de produse pentru atragerea unui număr mai mare de clienți","creșterea cu 10% a vânzărilor față de anul anterior pe un anumit segment al pieței","achiziția unui concurent pentru dominarea industriei","proiectarea și comercializarea la scară globală de soluții de consultanță profesională personalizate"],a:3,m:"Corect: D. Misiunea exprimă rațiunea de a fi a firmei — ce oferă și cui: „proiectarea și comercializarea la scară globală de soluții de consultanță profesională personalizate” (cap. 1). A și C sunt strategii, B este un obiectiv (cuantificat, cu termen)."}
  ]
}

};
